```cpp
#include <TensorFlowLite.h>
#include <tensorflow/lite/micro/all_ops_resolver.h>
#include <tensorflow/lite/micro/micro_error_reporter.h>
#include <tensorflow/lite/micro/micro_interpreter.h>
#include "model.h"
#include <Wire.h>
#include <Adafruit_APDS9960.h>

// Initialize APDS-9960 (RGB Color Sensor)
Adafruit_APDS9960 apds;

// TensorFlow Lite related variables
tflite::MicroErrorReporter micro_error_reporter;
const tflite::Model* model = tflite::GetModel(g_model);
tflite::AllOpsResolver resolver;
uint8_t tensor_arena[6000];
tflite::MicroInterpreter interpreter(model, resolver, tensor_arena, sizeof(tensor_arena), &micro_error_reporter);

// Input tensor
float input_data[3];  // Red, Green, Blue values

void setup() {
  Serial.begin(9600);

  // Initialize the APDS-9960
  if (!apds.begin()) {
    Serial.println("Failed to initialize APDS-9960 sensor!");
    while (1);
  }

  // Enable color sensing
  apds.enableColor(true);

  // Load and allocate model
  interpreter.AllocateTensors();

  // Verify the input tensor has the expected shape and type
  TfLiteTensor* input = interpreter.input(0);
  if ((input->dims->size != 2) || (input->dims->data[0] != 1) || (input->dims->data[1] != 3) ||
      (input->type != kTfLiteFloat32)) {
    Serial.println("Input tensor shape or type mismatch");
    while (1);
  }
}

void loop() {
  // Read color values from the sensor
  uint16_t r, g, b, c;
  if (!apds.colorGetRawData(&r, &g, &b, &c)) {
    Serial.println("Failed to get color data");
    return;
  }

  // Normalize the color values to [0.0, 1.0]
  float max_value = max(max(r, g), b);
  input_data[0] = r / (float)max_value;  // Red
  input_data[1] = g / (float)max_value;  // Green
  input_data[2] = b / (float)max_value;  // Blue

  // Copy the normalized color values to the model's input tensor
  float* input_buffer = interpreter.input(0)->data.f;
  for (int i = 0; i < 3; i++) {
    input_buffer[i] = input_data[i];
  }

  // Run inference
  if (interpreter.Invoke() != kTfLiteOk) {
    Serial.println("Invoke failed");
    return;
  }

  // Get the output from the model
  TfLiteTensor* output = interpreter.output(0);
  uint8_t predicted_class = output->data.uint8[0];

  // Print the result with corresponding emoji
  switch (predicted_class) {
    case 0:
      Serial.println("Apple 🍏");
      break;
    case 1:
      Serial.println("Banana 🍌");
      break;
    case 2:
      Serial.println("Orange 🍊");
      break;
    default:
      Serial.println("Unknown object");
      break;
  }

  delay(500);  // Wait for a short period before next inference
}
```

