```cpp
#include <TensorFlowLite.h>
#include <Wire.h>
#include <Adafruit_APDS9960.h>
#include "model.h"

// Define error reporter and model variables
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  error_reporter->Report("Model schema version (%d) not equal to supported version (%d).\n",
                         model->version(), TFLITE_SCHEMA_VERSION);
}

// Define tensor arena
uint8_t tensor_arena[4096];

// Create the interpreter with the model and tensor arena.
tflite::MicroMutableOpResolver<5> micro_op_resolver;
micro_op_resolver.AddBuiltin(tflite::BuiltinOperator_FULLY_CONNECTED, tflite::ops::micro::Register_FULLY_CONNECTED());
micro_op_resolver.AddBuiltin(tflite::BuiltinOperator_SOFTMAX, tflite::ops::micro::Register_SOFTMAX());

tflite::MicroInterpreter interpreter(model, micro_op_resolver, tensor_arena, sizeof(tensor_arena), error_reporter);

// Allocate memory for tensors
TfLiteStatus allocate_status = interpreter.AllocateTensors();
if (allocate_status != kTfLiteOk) {
  error_reporter->Report("AllocateTensors() failed\n");
}

// Define model inputs and outputs
TfLiteTensor* input = interpreter.input(0);
if ((input->dims->size != 1) || (input->dims->data[0] != 3)) {
  error_reporter->Report("Bad input tensor dims!\nExpected %d elements, got %d\n", 3, input->dims->data[0]);
}

// Initialize sensor
Adafruit_APDS9960 apds;

void setup() {
  Serial.begin(9600);

  if (!apds.begin()) {
    error_reporter->Report("Could not find a valid APDS-9960 sensor, check wiring!\n");
    while (1);
  }

  // Enable color sensing
  apds.enableColor(true);
}

void loop() {
  uint16_t r, g, b, c;
  if (!apds.colorGetRawData(&r, &g, &b, &c)) {
    error_reporter->Report("Could not get data from sensor\n");
    return;
  }

  // Normalize the color values to a range between 0 and 1
  float red = static_cast<float>(r) / c;
  float green = static_cast<float>(g) / c;
  float blue = static_cast<float>(b) / c;

  // Copy normalized color data into the input tensor
  input->data.f[0] = red;
  input->data.f[1] = green;
  input->data.f[2] = blue;

  // Run inference
  TfLiteStatus invoke_status = interpreter.Invoke();
  if (invoke_status != kTfLiteOk) {
    error_reporter->Report("Invoke failed!\n");
    return;
  }

  // Get output and map to class labels
  TfLiteTensor* output = interpreter.output(0);
  uint8_t predicted_class = static_cast<uint8_t>(output->data.uint8[0]);

  // Output the result using Unicode emojis
  switch (predicted_class) {
    case 0:
      Serial.println("🍎"); // Apple
      break;
    case 1:
      Serial.println("🍌"); // Banana
      break;
    case 2:
      Serial.println("🍊"); // Orange
      break;
    default:
      Serial.println("Unknown");
      break;
  }

  delay(1000); // Wait for a second before the next reading
}
```

