  // Normalize the color values to a range between 0 and 1
  float red = static_cast<float>(r) / c;
  float green = static_cast<float>(g) / c;
  float blue = static_cast<float>(b) / c;

  // Copy normalized color data into the input tensor
  input->data.f[0] = red;
  input->data.f[1] = green;
  input->data.f[2] = blue;

  // Run inference
  TfLiteStatus invoke_status = interpreter.Invoke();
  if (invoke_status != kTfLiteOk) {
    error_reporter->Report("Invoke failed!\n");
    return;
  }

  // Get output and map to class labels
  TfLiteTensor* output = interpreter.output(0);
  uint8_t predicted_class = static_cast<uint8_t>(output->data.uint8[0]);

