#include "model.h" // Ensure this path is correct

// Define the tensor arena size
constexpr int kTensorArenaSize = 4096;
uint8_t tensor_arena[kTensorArenaSize];

// Error reporter for logging errors
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Model and interpreter
const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  error_reporter->Report("Model schema version does not match expected version.\n");
}

// Op resolver for TensorFlow Lite Micro
tflite::AllOpsResolver resolver;

// Interpreter
tflite::MicroInterpreter interpreter(model, resolver, tensor_arena, kTensorArenaSize, error_reporter);

// APDS9960 sensor object
Adafruit_APDS9960 apds;

// Define a buffer to hold the input data
float input_data[3];

void setup() {
  // Start serial communication for debugging and output
  Serial.begin(9600);

  // Initialize the APDS-9960 sensor
  if (!apds.begin()) {
    error_reporter->Report("Failed to initialize APDS9960 sensor\n");
    while (1) delay(1000); // Halt execution on failure
  }
  apds.enableColor(true);

  // Allocate tensors for the model
  tflite::Status allocate_status = interpreter.AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    error_reporter->Report("AllocateTensors() failed\n");
    while (1) delay(1000); // Halt execution on failure
  }

  // Check input tensor details
  TfLiteTensor* input = interpreter.input(0);
  if ((input->type != kTfLiteFloat32) || (input->bytes / sizeof(float) != 3)) {
    error_reporter->Report("Bad input tensor parameters in model\n");
    while (1) delay(1000); // Halt execution on failure
  }

  Serial.println("Setup complete, ready to run inference.");
}

void loop() {
  uint16_t r = 0, g = 0, b = 0;
  if (!apds.colorGetRGB(&r, &g, &b)) {
    error_reporter->Report("Failed to get color data from APDS9960\n");
    delay(100);
    return;
  }

  // Normalize the RGB values (scale to [0.0, 1.0])
  float max_value = std::max({r, g, b});
  input_data[0] = static_cast<float>(r) / max_value; // Red
  input_data[1] = static_cast<float>(g) / max_value; // Green
  input_data[2] = static_cast<float>(b) / max_value; // Blue

  // Copy the input data into the model's input tensor buffer
  float* input_tensor = interpreter.input(0)->data.f;
  for (int i = 0; i < 3; ++i) {
    input_tensor[i] = input_data[i];
  }

  // Run inference
  if (interpreter.Invoke() != kTfLiteOk) {
    error_reporter->Report("Invoke failed.\n");
    delay(100);
    return;
  }

  // Get the output tensor
  TfLiteTensor* output = interpreter.output(0);
  int predicted_class = static_cast<int>(output->data.uint8[0]);

  // Map the prediction to an emoji and print it
  switch (predicted_class) {
    case 0: Serial.println("🍎 Apple"); break;
    case 1: Serial.println("🍌 Banana"); break;
    case 2: Serial.println("🍊 Orange"); break;
    default: Serial.println("Unknown class");
  }

  delay(500); // Delay between readings
}
