// Define the TensorFlow Lite Micro components
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Define a tensor arena for the interpreter to use for allocating tensors
const int kTensorArenaSize = 4096;
uint8_t tensor_arena[kTensorArenaSize];

// Declare global variables for sensor and model inference
Adafruit_APDS9960 apds;
tflite::MicroInterpreter* interpreter = nullptr;

// Define input and output buffers
float input_data[3]; // Red, Green, Blue values
int8_t output_data[1]; // Output class

void setup() {
  Serial.begin(9600);

  // Initialize the APDS9960 sensor
  if (!apds.begin()) {
    Serial.println("Failed to initialize APDS9960! Exiting...");
    while (1);
  }
  apds.enableColor(true); // Enable color sensing

  // Load the model from flash
  const tflite::Model* model = tflite::GetModel(g_model);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Model schema version does not match!");
    while (1);
  }

  // Create an instance of the interpreter
  static tflite::AllOpsResolver resolver;
  static tflite::MicroInterpreter static_interpreter(model, resolver, tensor_arena, kTensorArenaSize, error_reporter);
  interpreter = &static_interpreter;

  // Allocate tensors
  if (interpreter->AllocateTensors() != kTfLiteOk) {
    Serial.println("Failed to allocate tensors!");
    while (1);
  }

  // Verify input and output tensor details
  const int input_tensor_count = interpreter->inputs_size();
  const TfLiteTensor* input_tensor = interpreter->input(0);

  if ((input_tensor_count != 1) || (input_tensor->dims->size != 1) ||
      (input_tensor->dims->data[0] != 3) || (input_tensor->type != kTfLiteFloat32)) {
    Serial.println("Bad input tensor parameters!");
    while (1);
  }

  const int output_tensor_count = interpreter->outputs_size();
  const TfLiteTensor* output_tensor = interpreter->output(0);

  if ((output_tensor_count != 1) || (output_tensor->dims->size != 1) ||
      (output_tensor->dims->data[0] != 1) || (output_tensor->type != kTfLiteInt8)) {
    Serial.println("Bad output tensor parameters!");
    while (1);
  }
}

void loop() {
  uint16_t r, g, b, c;

  // Check if color data is ready
  if (!apds.colorDataReady()) {
    delay(20); // Wait for the next cycle if not ready
    return;
  }

  // Read color data from the sensor
  apds.getColorData(&r, &g, &b, &c);

  // Normalize RGB values (assuming max is 1024 as per APDS9960 datasheet)
  float r_norm = static_cast<float>(r) / 1023.0f;
  float g_norm = static_cast<float>(g) / 1023.0f;
  float b_norm = static_cast<float>(b) / 1023.0f;

  // Store normalized values in input tensor
  input_data[0] = r_norm;
  input_data[1] = g_norm;
  input_data[2] = b_norm;

  const TfLiteTensor* input_tensor = interpreter->input(0);
  for (int i = 0; i < 3; ++i) {
    input_tensor->data.f[i] = input_data[i];
  }

  // Run the inference
  if (interpreter->Invoke() != kTfLiteOk) {
    Serial.println("Inference failed!");
    return;
  }

  // Read the output tensor
  const TfLiteTensor* output_tensor = interpreter->output(0);
  int8_t predicted_class = output_tensor->data.i8[0];

  // Map class index to object name and print to serial
  switch (predicted_class) {
    case 0:
      Serial.println("Apple");
      break;
    case 1:
      Serial.println("Banana");
      break;
    case 2:
      Serial.println("Orange");
      break;
    default:
      Serial.println("Unknown class");
      break;
  }

  delay(500); // Delay for better readability
}
