#include <Wire.h>
#include <Adafruit_APDS9960.h>
#include "TensorFlowLite.h" // Include the base TensorFlow Lite library
#include "tensorflow/lite/micro/all_ops_resolver.h"
#include "tensorflow/lite/micro/micro_error_reporter.h"
#include "tensorflow/lite/micro/micro_interpreter.h"
#include "tensorflow/lite/schema/schema_generated.h"
#include "model.h" // Ensure your model is included correctly

// Define the TensorFlow Lite Micro components
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Define a tensor arena for the interpreter to use for allocating tensors
const int kTensorArenaSize = 4096;
uint8_t tensor_arena[kTensorArenaSize];

// Declare global variables for sensor and model inference
Adafruit_APDS9960 apds;
tflite::MicroInterpreter* interpreter = nullptr;

// Define input and output buffers
float input_data[3]; // Red, Green, Blue values
int8_t output_data[1]; // Output class

void setup() {
  Serial.begin(9600);

  // Initialize the APDS9960 sensor
  if (!apds.begin()) {
    Serial.println("Failed to initialize APDS9960! Exiting...");
    while (1);
  }
  apds.enableColor(true); // Enable color sensing

  // Load the model from flash
  const tflite::Model* model = tflite::GetModel(g_model_data); // Corrected to use g_model_data
  if (model->version() != TFLITE_SCHEMA_VERSION) { // Ensure TFLITE_SCHEMA_VERSION is defined
    Serial.println("Model schema version does not match!");
    while (1);
  }

  // Create an instance of the interpreter
  static tflite::AllOpsResolver resolver;
  static tflite::MicroInterpreter static_interpreter(model, resolver, tensor_arena, kTensorArenaSize, error_reporter);
  interpreter = &static_interpreter;

  // Allocate tensors
  if (interpreter->AllocateTensors() != kTfLiteOk) {
    Serial.println("Failed to allocate tensors!");
    while (1);
  }

  // Verify input and output tensor details
  const int input_tensor_count = interpreter->inputs_size();
  const TfLiteTensor* input_tensor = interpreter->input(0);

  if (input_tensor_count != 1 || input_tensor == nullptr) {
    Serial.println("Input tensor error!");
    while (1);
  }

  if (input_tensor->type != kTfLiteFloat32 || input_tensor->bytes / sizeof(float) != 3) {
    Serial.println("Input tensor format mismatch!");
    while (1);
  }

  const int output_tensor_count = interpreter->outputs_size();
  const TfLiteTensor* output_tensor = interpreter->output(0);

  if (output_tensor_count != 1 || output_tensor == nullptr) {
    Serial.println("Output tensor error!");
    while (1);
  }

  if (output_tensor->type != kTfLiteInt8 || output_tensor->bytes / sizeof(int8_t) != 1) {
    Serial.println("Output tensor format mismatch!");
    while (1);
  }
}

void loop() {
  uint16_t r, g, b, c;
  apds.getColorData(&r, &g, &b, &c);

  // Normalize the color values
  float sum = r + g + b;
  input_data[0] = static_cast<float>(r) / sum;
  input_data[1] = static_cast<float>(g) / sum;
  input_data[2] = static_cast<float>(b) / sum;

  // Copy the processed data into the model's input tensor buffer
  float* input = interpreter->input(0)->data.f;
  for (int i = 0; i < 3; ++i) {
    input[i] = input_data[i];
  }

  // Run the inference using interpreter.Invoke()
  if (interpreter->Invoke() != kTfLiteOk) {
    Serial.println("Inference error!");
    return;
  }

  // Interpret the model's output tensor(s)
  int8_t* output = interpreter->output(0)->data.int8;
  const char* fruit_name;
  switch (*output) {
    case 0:
      fruit_name = "Apple";
      break;
    case 1:
      fruit_name = "Banana";
      break;
    case 2:
      fruit_name = "Orange";
      break;
    default:
