```cpp
#include <TensorFlowLite.h>
#include <Wire.h>
#include <Adafruit_APDS9960.h>

// Include the model file
#include "model.h"

// Error reporter for logging
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Model pointer and interpreter
const tflite::Model* model = nullptr;
tflite::MicroInterpreter* interpreter = nullptr;

// Define tensor arena size
constexpr int kTensorArenaSize = 4096;
uint8_t tensor_arena[kTensorArenaSize];

// APDS-9960 RGB sensor object
Adafruit_APDS9960 apds;

// Input and output tensors
float* input_tensor;

void setup() {
  // Initialize serial communication
  Serial.begin(9600);

  // Initialize the APDS-9960 (RGB Sensor)
  if (!apds.begin()) {
    Serial.println("Failed to initialize sensor! Exiting...");
    while (1);
  }

  apds.enableColor(true);  // Enable color sensor

  // Load model
  model = tflite::GetModel(model_data);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    error_reporter->Report("Model schema version %d not supported\n", model->version());
    return;
  }

  // Resolve the model's operator nodes
  static tflite::MicroMutableOpResolver<2> micro_op_resolver;
  micro_op_resolver.AddFullyConnected();
  micro_op_resolver.AddSoftmax();

  // Create an interpreter to run the model
  static tflite::MicroInterpreter static_interpreter(
      model, micro_op_resolver, tensor_arena, kTensorArenaSize, error_reporter);
  interpreter = &static_interpreter;

  // Allocate tensors
  if (interpreter->AllocateTensors() != kTfLiteOk) {
    error_reporter->Report("AllocateTensors() failed\n");
    return;
  }

  // Assign the model's input tensor buffer to the `input_tensor` variable
  input_tensor = interpreter->typed_input_tensor<float>(0);
}

void loop() {
  uint16_t r, g, b, c;

  // Read color sensor values
  if (!apds.getColor(&r, &g, &b, &c)) {
    Serial.println("Failed to read color!");
    return;
  }

  // Normalize the RGB values to be between 0 and 1
  float red = r / static_cast<float>(65535);
  float green = g / static_cast<float>(65535);
  float blue = b / static_cast<float>(65535);

  // Set input tensor data
  input_tensor[0] = red;
  input_tensor[1] = green;
  input_tensor[2] = blue;

  // Run the inference
  if (interpreter->Invoke() != kTfLiteOk) {
    error_reporter->Report("Invoke failed\n");
    return;
  }

  // Get output tensor data
  uint8_t* output = interpreter->typed_output_tensor<uint8_t>(0);
  int predicted_class = output[0];

  // Map the prediction to an emoji and print it
  switch (predicted_class) {
    case 0:
      Serial.print("🍎 ");  // Apple emoji
      break;
    case 1:
      Serial.print("🍌 ");  // Banana emoji
      break;
    case 2:
      Serial.print("🍊 ");  // Orange emoji
      break;
    default:
      Serial.print("Unknown");
      break;
  }

  Serial.println();
  delay(1000);  // Delay for 1 second before next reading
}
```

