#include "tensorflow/lite/micro/micro_error_reporter.h"
#include "tensorflow/lite/micro/micro_interpreter.h"
#include "model.h"  // Include the generated model header

// Define and allocate a tensor arena buffer
constexpr int kTensorArenaSize = 4096;
uint8_t tensor_arena[kTensorArenaSize];

// Create an error reporter instance
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Instantiate the model from the generated header file
const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  TF_LITE_REPORT_ERROR(error_reporter, "Model schema version (%d) doesn't match expected version (%d)",
                       model->version(), TFLITE_SCHEMA_VERSION);
}

// Create an instance of the AllOpsResolver to resolve all operations
tflite::ops::micro::AllOpsResolver resolver;

// Create a MicroInterpreter object with the model and resolver
static tflite::MicroInterpreter static_interpreter(model, resolver, tensor_arena, kTensorArenaSize, error_reporter);
tflite::MicroInterpreter* interpreter = &static_interpreter;

// Allocate memory for tensors
TfLiteStatus allocate_status = interpreter->AllocateTensors();
if (allocate_status != kTfLiteOk) {
  TF_LITE_REPORT_ERROR(error_reporter, "AllocateTensors() failed");
}

// Get pointers to the model's input and output tensors
TfLiteTensor* input = interpreter->input(0);
TfLiteTensor* output = interpreter->output(0);

// Initialize APDS9960 sensor
Adafruit_APDS9960 apds;

void setup() {
  // Start serial communication for debugging
  Serial.begin(9600);

  // Initialize the APDS-9960 sensor
  if (!apds.init()) {
    Serial.println("Failed to initialize APDS9960 sensor!");
    while (1);
  }

  // Enable color sensing
  apds.enableColor(true);

  // Set gain and integration time for color measurements
  apds.setGain(GAIN_4X);
  apds.setIntegrationTime(INTEGRATIONTIME_700MS);

  // Check if the tensors are properly allocated
  if ((input->type != kTfLiteFloat32) || (output->type != kTfLiteUInt8)) {
    TF_LITE_REPORT_ERROR(error_reporter, "Model's input or output tensor has unexpected type");
    return;
  }

  // Ensure the input tensor has the correct dimensions
  if ((input->dims->size != 2) || (input->dims->data[0] != 1) || (input->dims->data[1] != 3)) {
    TF_LITE_REPORT_ERROR(error_reporter, "Model's input tensor has unexpected shape");
    return;
  }

  // Ensure the output tensor has the correct dimensions
  if ((output->dims->size != 2) || (output->dims->data[0] != 1) || (output->dims->data[1] != 1)) {
    TF_LITE_REPORT_ERROR(error_reporter, "Model's output tensor has unexpected shape");
    return;
  }
}

void loop() {
  // Check if color data is ready
  if (!apds.colorDataReady()) {
    delay(50);
    return;
