  float red = static_cast<float>(r) / c;
  float green = static_cast<float>(g) / c;
  float blue = static_cast<float>(b) / c;

  // Copy the processed data into the model's input tensor buffer
  input->data.f[0] = red;
  input->data.f[1] = green;
  input->data.f[2] = blue;

  // Invoke interpreter to run inference
  TfLiteStatus invoke_status = interpreter->Invoke();
  if (invoke_status != kTfLiteOk) {
    TF_LITE_REPORT_ERROR(error_reporter, "Invoke failed\n");
    return;
  }

  // Process output and map to class labels
  uint8_t predicted_class = output->data.uint8[0];
  switch (predicted_class) {
    case 0:
      Serial.println("Apple \uF8FF");  // Unicode emoji for Apple
      break;
    case 1:
