#include <Wire.h>
#include <Adafruit_APDS9960.h>
#include "tensorflow/lite/micro/all_ops_resolver.h"
#include "tensorflow/lite/micro/micro_error_reporter.h"
#include "tensorflow/lite/micro/micro_interpreter.h"
#include "tensorflow/lite/schema/schema_generated.h"
#include "model.h"  // Ensure this path is correct

// Define the size of the tensor arena (memory pool for input, output, and intermediate tensors)
const int tensor_arena_size = 4096;
uint8_t tensor_arena[tensor_arena_size];

// Create an error reporter
tflite::MicroErrorReporter micro_error_reporter;

// Map the model into a usable data structure. This doesn't involve actually allocating any memory.
const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  TF_LITE_REPORT_ERROR(&micro_error_reporter,
                       "Model provided is schema version %d not equal "
                       "to supported version %d.",
                       model->version(), TFLITE_SCHEMA_VERSION);
}

// Pull in all the operation implementations we need.
tflite::ops::micro::AllOpsResolver resolver;

// Create an interpreter to run the model with
tflite::MicroInterpreter interpreter(model, resolver, tensor_arena,
                                     tensor_arena_size, &micro_error_reporter);

// Allocate memory from the tensor_arena for the model's tensors
interpreter.AllocateTensors();

// Get pointers to input and output tensors
 TfLiteTensor* input = interpreter.input(0);
if (input->type != kTfLiteFloat32) {
  TF_LITE_REPORT_ERROR(&micro_error_reporter, "Input tensor not float32");
}

TfLiteTensor* output = interpreter.output(0);
if (output->type != kTfLiteUInt8) {
  TF_LITE_REPORT_ERROR(&micro_error_reporter, "Output tensor not uint8");
}

// Initialize the APDS9960 sensor
Adafruit_APDS9960 apds;

void setup() {
  Serial.begin(9600);

  // Initialize and configure the APDS9960 RGB sensor
  if (!apds.begin()) {
    Serial.println("Error initializing APDS-9960! Exiting...");
    while (1);
  }
  Serial.println("APDS-9960 Initialization complete");

  // Enable color module
  apds.enableColor(true);

  // Wait for initial calibration
  delay(2000);
}

void loop() {
  uint16_t r, g, b, c;

  // Read the RGB values from the sensor
  if (!apds.colorGetRawData(&r, &g, &b, &c)) {
    Serial.println("Error reading color data");
    return;
  }

  // Normalize the RGB values to the range [0.0, 1.0]
  float red = static_cast<float>(r) / c;
  float green = static_cast<float>(g) / c;
  float blue = static_cast<float>(b) / c;

  // Copy normalized RGB values into the model's input tensor
  input->data.f[0] = red;
  input->data.f[1] = green;
  input->data.f[2] = blue;

  // Run inference
  TfLiteStatus invoke_status = interpreter.Invoke();
  if (invoke_status != kTfLiteOk) {
    TF_LITE_REPORT_ERROR(&micro_error_reporter, "Invoke failed");
    return;
  }

  // Get the classification result from the output tensor
  uint8_t predicted_class = output->data.uint8[0];

  // Map the predicted class to a human-readable label and print it
  switch (predicted_class) {
    case 0:
      Serial.println("Apple \xF0\x9F\x8D\x45");  // Apple emoji
