```cpp
#include <TensorFlowLite.h>
#include <tensorflow/lite/micro/all_ops_resolver.h>
#include <tensorflow/lite/micro/micro_error_reporter.h>
#include <tensorflow/lite/micro/micro_interpreter.h>
#include "model.h"
#include <Wire.h>
#include <SparkFun_APDS9960.h>

// Constants
#define BAUD_RATE 9600
const int tensor_arena_size = 6000;
uint8_t tensor_arena[tensor_arena_size];

// TensorFlow Lite objects
tflite::MicroErrorReporter error_reporter;
const tflite::Model* model = tflite::GetModel(g_model);
tflite::AllOpsResolver resolver;
tflite::MicroInterpreter interpreter(model, resolver, tensor_arena, tensor_arena_size, &error_reporter);

// APDS9960 sensor
SparkFun_APDS9960 apds = SparkFun_APDS9960();

// Variables to hold the RGB values
uint16_t red_value = 0;
uint16_t green_value = 0;
uint16_t blue_value = 0;

void setup() {
  Serial.begin(BAUD_RATE);

  // Initialize APDS-9960 (configure I2C and interrupts)
  if (apds.init()) {
    Serial.println("APDS-9960 initialization complete");
  } else {
    Serial.println("Something went wrong during APDS-9960 init!");
  }

  // Start running the APDS-9960 light sensor (no interrupts)
  apds.enableColorSensor(25);

  // Load and allocate memory for the model
  if (interpreter.AllocateTensors() != kTfLiteOk) {
    Serial.println("Failed to allocate tensors!");
    while (1);
  }

  // Verify input tensor requirements
  TfLiteTensor* input = interpreter.input(0);
  if ((input->type != kTfLiteFloat32) || (input->bytes / sizeof(float) != 3)) {
    Serial.println("Bad input tensor parameters");
    while (1);
  }
}

void loop() {
  // Read RGB values from the sensor
  if (!apds.readColor(red_value, green_value, blue_value)) {
    Serial.println("Error reading color data");
  } else {
    // Normalize RGB values to [0, 1]
    float normalized_red = red_value / 65535.0f;
    float normalized_green = green_value / 65535.0f;
    float normalized_blue = blue_value / 65535.0f;

    // Set the input tensor data
    float* input_data = interpreter.input(0)->data.f;
    input_data[0] = normalized_red;
    input_data[1] = normalized_green;
    input_data[2] = normalized_blue;

    // Run the inference
    if (interpreter.Invoke() != kTfLiteOk) {
      Serial.println("Invoke failed!");
    }

    // Get the output tensor data
    TfLiteTensor* output = interpreter.output(0);
    uint8_t predicted_class = output->data.uint8[0];

    // Map the class index to a fruit name and print emoji
    if (predicted_class == 0) {
      Serial.println("Apple \uF8FF");  // Apple emoji
    } else if (predicted_class == 1) {
      Serial.println("Banana \uD83C\uDF4C");  // Banana emoji
    } else if (predicted_class == 2) {
      Serial.println("Orange \uD83C\uDF4A");  // Orange emoji
    } else {
      Serial.println("Unknown class");
    }
  }

  delay(1000);  // Delay between readings
}
```

