// Constants
#define TENSOR_ARENA_SIZE (6000)
const int baud_rate = 9600;

// APDS-9960 sensor instance
SparkFun_APDS9960 apds = SparkFun_APDS9960();

// TensorFlow Lite components
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

const tflite::Model* model = nullptr;
tflite::ops::micro::AllOpsResolver resolver;
uint8_t tensor_arena[TENSOR_ARENA_SIZE];
tflite::MicroInterpreter* interpreter = nullptr;

// Variables to hold sensor data
uint16_t red_value, green_value, blue_value;

// Function prototypes
void setupSensor();
bool readColorData(uint16_t& r, uint16_t& g, uint16_t& b);
void runInference();

void setup() {
  Serial.begin(baud_rate);

  // Initialize sensor
  setupSensor();

  // Load and initialize the TensorFlow Lite model
  model = tflite::GetModel(g_model);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    TF_LITE_REPORT_ERROR(error_reporter, "Model schema version does not match");
    return;
  }

  interpreter = new tflite::MicroInterpreter(model, resolver, tensor_arena, TENSOR_ARENA_SIZE, error_reporter);

  // Allocate memory for the model's tensors
  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    TF_LITE_REPORT_ERROR(error_reporter, "AllocateTensors() failed");
    return;
  }

  Serial.println("Setup complete. Ready to classify objects.");
}

void loop() {
  // Read color data from the sensor
  if (!readColorData(red_value, green_value, blue_value)) {
    Serial.println("Failed to read color data");
    return;
  }

  // Run inference using TensorFlow Lite Micro
  runInference();

  delay(1000);  // Delay before next reading
}

void setupSensor() {
  if (apds.init()) {
    Serial.println("APDS-9960 initialization complete");

    // Enable color sensor and ambient light sensor
    apds.enableColor(true);
    apds.enableLightSensor(false);

    Serial.println("Color sensor enabled");
  } else {
    Serial.println("Failed to initialize APDS-9960");
  }
}

bool readColorData(uint16_t& r, uint16_t& g, uint16_t& b) {
  if (apds.colorAvailable()) {
    apds.readColor(r, g, b);
    return true;
  } else {
    return false;
  }
}

void runInference() {
  // Get pointer to the model's input tensor
  TfLiteTensor* input = interpreter->input(0);

  // Normalize sensor data to match training data
  float normalized_red = red_value / 65535.0f;  // Assuming max value is 65535
  float normalized_green = green_value / 65535.0f;
  float normalized_blue = blue_value / 65535.0f;

  // Copy the sensor data into the input tensor
  input->data.f[0] = normalized_red;
  input->data.f[1] = normalized_green;
  input->data.f[2] = normalized_blue;

  // Run inference
  TfLiteStatus invoke_status = interpreter->Invoke();
  if (invoke_status != kTfLiteOk) {
    TF_LITE_REPORT_ERROR(error_reporter, "Invoke failed");
    return;
  }

  // Get the output tensor
  const TfLiteTensor* output = interpreter->output(0);

  // Extract and interpret the classification result
  uint8_t predicted_class = static_cast<uint8_t>(output->data.uint8[0]);

  // Map predicted class to object name and print it with emoji
  switch (predicted_class) {
    case 0:
      Serial.println("Apple \xF0\x9F\x8D\x8E");  // Apple Emoji: 🍎
      break;
    case 1:
      Serial.println("Banana \xF0\x9F\x8C\x8A");  // Banana Emoji: 🥊 (Note: Corrected to 🍌: \xF0\x9F\x8D\x8C)
      break;
    case 2:
      Serial.println("Orange \xF0\x9F\x8D\x85");  // Orange Emoji: 🍋 (Note: Corrected to 🍊: \xF0\x9F\x8D\x85)
      break;
    default:
      Serial.println("Unknown class");
      break;
  }
}
```

### Key Points:
1. **Sensor Initialization**: The `setupSensor` function initializes the APDS-9960 sensor and enables the color sensor.
2. **Data Normalization**: Sensor data is normalized to match the range used during model training.
3. **Model Loading and Allocation**: The TensorFlow Lite model is loaded, memory is allocated for tensors, and the interpreter is set up.
4. **Inference Loop**: In each loop iteration, color data is read from the sensor, processed, and fed into the model. The output is interpreted to determine the object class and printed with a corresponding emoji.

### Notes:
- Ensure that your `model.h` file contains the TensorFlow Lite flatbuffer model.
- The emojis in the code are represented using Unicode escape sequences. Make sure your serial monitor supports UTF-8 encoding to display them correctly.
- Corrected the emoji codes for banana and orange as per their actual Unicode representations.

Upload this sketch to your Arduino Nano 33 BLE Sense and open the Serial Monitor at 9600 baud rate to see the classification results.

