#include <Wire.h>
#include <SparkFun_APDS9960.h>
#include <TensorFlowLite.h>
#include "tensorflow/lite/micro/all_ops_resolver.h"
#include "tensorflow/lite/micro/micro_error_reporter.h"
#include "tensorflow/lite/micro/micro_interpreter.h"
#include "model.h"  // This should be your generated model header file

// Define the sensor
SparkFun_APDS9960 apds = SparkFun_APDS9960();

// Create an area of memory to use for input, output, and intermediate arrays.
constexpr int kTensorArenaSize = 6000;
uint8_t tensor_arena[kTensorArenaSize];

// Error reporter
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Model and interpreter objects
const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  error_reporter->Report("Model schema version not supported\n");
}

tflite::AllOpsResolver resolver;
tflite::MicroInterpreter interpreter(model, resolver, tensor_arena, kTensorArenaSize, error_reporter);

// Allocate memory for the model
if (interpreter.AllocateTensors() != kTfLiteOk) {
  error_reporter->Report("AllocateTensors() failed\n");
}

void setup() {
  Serial.begin(9600);

  // Initialize APDS-9960 (configure I2C and turn on the LED)
  if (!apds.init()) {
    Serial.println("Failed to initialize APDS-9960 sensor!");
    while (1);  // Halt program
  }
  apds.enableColor(true);

  // Wait for initialization
  delay(500);
}

void loop() {
  uint16_t red, green, blue;

  if (!apds.colorAvailable()) {
    return;
  }

  apds.getColorData(&red, &green, &blue);

  // Normalize RGB values to be in the range [0, 1]
  float normalized_red = static_cast<float>(red) / 65535.0f;
  float normalized_green = static_cast<float>(green) / 65535.0f;
  float normalized_blue = static_cast<float>(blue) / 65535.0f;

  // Get pointer to the model's input tensor
  TfLiteTensor* input_tensor = interpreter.input(0);

  // Copy normalized RGB values into the model's input tensor
  input_tensor->data.f[0] = normalized_red;
  input_tensor->data.f[1] = normalized_green;
  input_tensor->data.f[2] = normalized_blue;

  // Run inference
  if (interpreter.Invoke() != kTfLiteOk) {
    error_reporter->Report("Invoke failed\n");
  }

  // Get pointer to the model's output tensor
  TfLiteTensor* output_tensor = interpreter.output(0);

  int predicted_class = static_cast<int>(output_tensor->data.uint8[0]);

  // Output the predicted class as a Unicode emoji
  switch (predicted_class) {
    case 0:
      Serial.println("Apple \uF8FF");  // Use appropriate emoji code for Apple
      break;
    case 1:
      Serial.println("Banana \uD83C\uDF4C");
      break;
    case 2:
      Serial.println("Orange \uD83C\uDF4A");
      break;
    default:
      Serial.println("Unknown class");
  }

  delay(1000);  // Delay between readings
}
