#include <TensorFlowLite.h>
#include <Wire.h>
#include "Arduino_LSM9DS1.h"
#include "model.h"

// Phase 1: Initialization

// Variables for TensorFlow Lite Micro
tflite::ErrorReporter error_reporter;
const tflite::Model* model = nullptr;
tflite::MicroInterpreter* interpreter = nullptr;
TfLiteTensor* input = nullptr;
TfLiteTensor* output = nullptr;

// Define tensor arena buffer with a carefully chosen size
uint8_t tensor_arena[8000];

void setup() {
  // Initialize Serial for debugging and communication
  Serial.begin(9600);

  // Load the model from the provided path
  model = tflite::GetModel(g_model);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    error_reporter.Report("Model schema version not supported");
    return;
  }

  // Register the necessary operators for the model
  static tflite::MicroOpResolver<5> resolver;
  resolver.AddDense();
  resolver.AddSoftmax();

  // Instantiate the interpreter with the model, operator resolver, tensor arena, and error reporter
  static tflite::MicroInterpreter static_interpreter(model, resolver, tensor_arena, sizeof(tensor_arena), &error_reporter);
  interpreter = &static_interpreter;

  // Allocate memory for tensors using the tensor arena
  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    error_reporter.Report("AllocateTensors() failed");
    return;
  }

  // Define model inputs and outputs
  input = interpreter->input(0);
  output = interpreter->output(0);

  // Phase 1.9: Set Up Other Relevant Parts - Initialize the Color Sensor (example setup)
  if (!LSM.begin()) {
    Serial.println("Failed to initialize LSM9DS1!");
    while (true);
  }

  // Additional sensor setup can be done here
}

void loop() {
  // Phase 2: Preprocessing

  // Example of reading RGB values from a color sensor
  float red = analogRead(A0) / 1023.0;
  float green = analogRead(A1) / 1023.0;
  float blue = analogRead(A2) / 1023.0;

  // Normalize the RGB values based on dataset statistics
  float norm_red = (red - 0.5623661971830984) / 0.028464634416673053;
  float norm_green = (green - 0.23716901408450702) / 0.021283115987959598;
  float norm_blue = (blue - 0.200056338028169) / 0.019259793296579324;

