float* input = interpreter.input(0)->data.f;
int8_t* output = interpreter.output(0)->data.int8;

// Initialize APDS9960 color sensor
Adafruit_APDS9960 apds;

void setup() {
  // Start serial communication for debugging
  Serial.begin(9600);

