  Serial.println(F("Initializing color sensor..."));
  if (!apds.begin()) {
    Serial.println(F("Failed to initialize color sensor! Exiting..."));
    while (1);
  }
  Serial.println(F("Color sensor initialized!"));

  // Enable the color sensor module
  apds.enableColor(true);

  // Set integration time to 50 ms and gain to 4x for better accuracy
  apds.setIntegrationTime(APDS9960_INTEGRATIONTIME_50MS);
  apds.setGain(APDS9960_GAIN_4X);
}

void loop() {
  uint16_t red, green, blue;

  // Read the color sensor data
  if (!apds.colorAvailable()) {
    delay(50);  // Wait for color data to be ready
    return;
  }

  apds.getColorData(&red, &green, &blue);

  // Normalize the RGB values to [0.0, 1.0] range
  float max_color = max(max(red, green), blue);
  input[0] = red / (float)max_color;
  input[1] = green / (float)max_color;
  input[2] = blue / (float)max_color;

  // Run inference
  if (interpreter.Invoke() != kTfLiteOk) {
    error_reporter->Report("Invoke failed\n");
    return;
  }

  // Process the output
