```cpp
#include <Arduino.h>
#include <Wire.h>
#include <TensorFlowLite.h>
#include <tensorflow/lite/micro/all_ops_resolver.h>
#include <tensorflow/lite/micro/micro_error_reporter.h>
#include <tensorflow/lite/micro/micro_interpreter.h>

// Include the model header file
#include "model.h"

// Error reporter for logging
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Model pointer and interpreter
const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  TF_LITE_REPORT_ERROR(error_reporter,
                       "Model provided is schema version %d not equal "
                       "to supported version %d.",
                       model->version(), TFLITE_SCHEMA_VERSION);
}

// Define tensor arena size
constexpr int kTensorArenaSize = 8000;
uint8_t tensor_arena[kTensorArenaSize];

// Op resolver and interpreter
tflite::AllOpsResolver resolver;
tflite::MicroInterpreter interpreter(model, resolver, tensor_arena, kTensorArenaSize, error_reporter);

// Input and output tensors
TfLiteTensor* input_tensor = interpreter.input(0);
if ((input_tensor->dims->size != 1) || (input_tensor->dims->data[0] != 3)) {
  TF_LITE_REPORT_ERROR(error_reporter, "Bad input tensor parameters in model");
}

// Function to read color sensor data
void readColorSensor(float* red, float* green, float* blue) {
    // Placeholder for actual color sensor reading logic
    *red = random(500, 637) / 1000.0;   // Simulate Red value between 0.5 and 0.636
    *green = random(182, 292) / 1000.0;  // Simulate Green value between 0.182 and 0.292
    *blue = random(167, 250) / 1000.0;   // Simulate Blue value between 0.167 and 0.25
}

void setup() {
    Serial.begin(9600);

    // Allocate tensors
    TfLiteStatus allocate_status = interpreter.AllocateTensors();
    if (allocate_status != kTfLiteOk) {
        TF_LITE_REPORT_ERROR(error_reporter, "AllocateTensors() failed");
        while (1);
    }

    // Verify input tensor size and type
    if ((input_tensor->dims->size != 1) || (input_tensor->dims->data[0] != 3)) {
        TF_LITE_REPORT_ERROR(error_reporter, "Bad input tensor parameters in model");
        while (1);
    }
}

void loop() {
    float red, green, blue;

    // Read color sensor data
    readColorSensor(&red, &green, &blue);

    // Fill the input tensor with sensor data
    float* input = interpreter.input(0)->data.f;
    input[0] = red;
    input[1] = green;
    input[2] = blue;

    // Run inference
    TfLiteStatus invoke_status = interpreter.Invoke();
    if (invoke_status != kTfLiteOk) {
        TF_LITE_REPORT_ERROR(error_reporter, "Invoke failed");
        while (1);
    }

    // Get the output tensor and classify the object
    TfLiteTensor* output_tensor = interpreter.output(0);
    uint8_t predicted_class = output_tensor->data.uint8[0];

    // Print the result with emojis
    switch (predicted_class) {
        case 0:
            Serial.println(F("\uD83C\uDF4E Apple \uD83C\uDF4E"));  // Apple Emoji
            break;
        case 1:
            Serial.println(F("\uD83C\uDF4C Banana \uD83C\uDF4C"));  // Banana Emoji
            break;
        case 2:
            Serial.println(F("\uD83C\uDF4A Orange \uD83C\uDF4A"));  // Orange Emoji
            break;
        default:
            Serial.println("Unknown class");
    }

    delay(1000);  // Delay before the next inference loop
}
