```cpp
#include <TensorFlowLite.h>
#include <tensorflow/lite/micro/micro_error_reporter.h>
#include <tensorflow/lite/micro/micro_interpreter.h>
#include <tensorflow/lite/micro/all_ops_resolver.h>
#include <Arduino_APDS9960.h>

#include "model.h"

// Create an area of memory to use for input, output, and intermediate arrays.
constexpr int kTensorArenaSize = 6000;
uint8_t tensor_arena[kTensorArenaSize];

// Global variables
tflite::ErrorReporter* error_reporter = nullptr;
const tflite::Model* model = nullptr;
tflite::MicroInterpreter* interpreter = nullptr;
TfLiteTensor* input = nullptr;

Arduino_APDS9960 apds = Arduino_APDS9960();

void setup() {
  // Initialize Serial communication
  Serial.begin(9600);

  // Setup Error Reporter
  error_reporter = tflite::GetMicroErrorReporter();

  // Load the model from flash memory into a tflite::Model object
  model = tflite::GetModel(g_model);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    error_reporter->Report("Model schema version (%d) not equal to supported version (%d).\n",
                           model->version(), TFLITE_SCHEMA_VERSION);
    return;
  }

  // Pull in all the operation implementations we need
  tflite::AllOpsResolver resolver;

  // Build an interpreter to run the model with
  static tflite::MicroInterpreter static_interpreter(
      model, resolver, tensor_arena, kTensorArenaSize, error_reporter);
  interpreter = &static_interpreter;

  // Allocate memory from the tensor_arena for the model's tensors
  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    error_reporter->Report("AllocateTensors() failed\n");
    return;
  }

  // Get a pointer to the input tensor
  input = interpreter->input(0);

  // Initialize color sensor
  if (!apds.init()) {
    Serial.println("APDS9960 initialization failed!");
    while (1);
  }
}

void loop() {
  uint16_t red, green, blue;

  // Read RGB values from the sensor
  apds.readColor(&red, &green, &blue);

  // Normalize the color values to [0.0, 1.0]
  float normalized_red = static_cast<float>(red) / 65535.0f;
  float normalized_green = static_cast<float>(green) / 65535.0f;
  float normalized_blue = static_cast<float>(blue) / 65535.0f;

  // Copy the normalized color values to the model's input tensor
  input->data.f[0] = normalized_red;
  input->data.f[1] = normalized_green;
  input->data.f[2] = normalized_blue;

  // Run inference
  TfLiteStatus invoke_status = interpreter->Invoke();
  if (invoke_status != kTfLiteOk) {
    error_reporter->Report("Invoke failed\n");
    return;
  }

  // Get the output from the model's output tensor
  TfLiteTensor* output = interpreter->output(0);
  int predicted_class = output->data.uint8[0];

  // Map the predicted class to a Unicode emoji and print it
  switch (predicted_class) {
    case 0: Serial.println("🍎"); break;  // Apple
    case 1: Serial.println("🍌"); break;  // Banana
    case 2: Serial.println("🍊"); break;  // Orange
    default: Serial.println("Unknown"); break;
  }

  // Small delay to prevent flooding serial output
  delay(500);
}
