  float normalized_red = static_cast<float>(red) / 65535.0f;
  float normalized_green = static_cast<float>(green) / 65535.0f;
  float normalized_blue = static_cast<float>(blue) / 65535.0f;

  // Copy the processed color values into the input tensor
  float* input_data = input->data.f;
  input_data[0] = normalized_red;
  input_data[1] = normalized_green;
  input_data[2] = normalized_blue;

  // Run inference
  TfLiteStatus invoke_status = interpreter->Invoke();
  if (invoke_status != kTfLiteOk) {
    error_reporter->Report("Invoke failed on index: %d\n", i);
    return;
  }

  // Get the output value from the model
  uint8_t predicted_class = *output->data.uint8;

