#include <TensorFlowLite.h>
#include <tensorflow/lite/micro/all_ops_resolver.h>
#include <tensorflow/lite/micro/micro_error_reporter.h>
#include <tensorflow/lite/micro/micro_interpreter.h>
#include "model.h"
#include <Wire.h>
#include <Adafruit_APDS9960.h>

// Define the TensorFlow Lite Micro Error Reporter and OpResolver
tflite::MicroErrorReporter micro_error_reporter;
tflite::AllOpsResolver resolver;

// Create an area of memory to use for input, output, and intermediate arrays.
constexpr int tensor_arena_size = 16384;
uint8_t tensor_arena[tensor_arena_size];

// Instantiate the interpreter
const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  micro_error_reporter.ReportError("Model schema version does not match");
  return;
}

tflite::MicroInterpreter interpreter(model, resolver, tensor_arena, tensor_arena_size, &micro_error_reporter);

// Allocate memory for the model
TfLiteStatus allocate_status = interpreter.AllocateTensors();
if (allocate_status != kTfLiteOk) {
  micro_error_reporter.ReportError("AllocateTensors() failed");
  return;
}

// Create an instance of the color sensor
Adafruit_APDS9960 apds;

// Define input tensor and output tensor pointers
float* input = interpreter.input(0)->data.f;
uint8_t* output = interpreter.output(0)->data.uint8;

void setup() {
  // Start serial communication for debugging/output
  Serial.begin(9600);

  // Initialize the color sensor
  if (!apds.begin()) {
    Serial.println("Failed to initialize APDS9960!");
    while (1);
  }

  // Enable color sensing and set gain
  apds.enableColor(true);
  apds.setGain(GAIN_4X);

  // Allocate memory for tensors
  if (interpreter.AllocateTensors() != kTfLiteOk) {
    micro_error_reporter.ReportError("AllocateTensors() failed");
    while (1);
  }
}

void loop() {
  uint16_t r, g, b, c;

  // Read the color sensor data
  if (!apds.colorRead(&r, &g, &b, &c)) {
    Serial.println("Failed to read color!");
    return;
  }

  // Normalize the RGB values to [0, 1]
  float sum = r + g + b;
  input[0] = static_cast<float>(r) / sum;
  input[1] = static_cast<float>(g) / sum;
  input[2] = static_cast<float>(b) / sum;

  // Run the inference
  if (interpreter.Invoke() != kTfLiteOk) {
    micro_error_reporter.ReportError("Invoke failed.");
    return;
  }

  // Process the output and print the result
  uint8_t class_id = output[0];
  switch (class_id) {
    case 0:
      Serial.println("\uF8FF Apple"); // Apple emoji
      break;
    case 1:
      Serial.println("\uD83C\uDF4C Banana"); // Banana emoji
      break;
    case 2:
      Serial.println("\uD83C\uDF4A Orange"); // Orange emoji
      break;
    default:
      Serial.println("Unknown");
  }

  // Delay for a bit before the next reading
  delay(1000);
}
