  Serial.begin(9600);

  if (!apds.begin()) {
    Serial.println("Failed to initialize APDS-9960 sensor!");
    while (1) delay(10);
  }

  // Set gesture parameters
  apds.enableColor(true);

  // Wait for the sensor to stabilize
  delay(100);
}

void loop() {
  uint16_t r, g, b, c;

  if (!apds.getColor(&r, &g, &b, &c)) {
    Serial.println("Failed to read color data from APDS-9960 sensor!");
    return;
  }

  // Normalize the RGB values
  float sum = r + g + b;
  float normalized_r = r / sum;
  float normalized_g = g / sum;
  float normalized_b = b / sum;

  // Copy the processed data into the model's input tensor buffer
  float* input_data = input->data.f;
  input_data[0] = normalized_r;
  input_data[1] = normalized_g;
  input_data[2] = normalized_b;

  // Run the inference
  TfLiteStatus invoke_status = interpreter.Invoke();
  if (invoke_status != kTfLiteOk) {
    error_reporter->Report("Invoke failed\n");
    return;
  }

  // Process the output tensor(s)
  uint8_t predicted_class = *output->data.uint8;

  // Output the result
