  apds.enableColor(true);

  // Load the model
  TF_LITE_REPORT_ERROR(error_reporter, "Model initialized");

  // Allocate memory for tensors
  if (interpreter.AllocateTensors() != kTfLiteOk) {
    TF_LITE_REPORT_ERROR(error_reporter, "AllocateTensors() failed");
  }

  // Ensure input tensor is float and has the expected dimensions
  if ((interpreter.input(0)->type != kTfLiteFloat32) ||
      (interpreter.input(0)->bytes / sizeof(float) != 3)) {
    TF_LITE_REPORT_ERROR(error_reporter, "Bad input tensor parameters in model");
  }
}

void loop() {
  // Variables to store color data
  uint16_t r, g, b, c;

  // Read the color
  if (!apds.getColor(&r, &g, &b, &c)) {
    Serial.println("Failed to get color data from APDS-9960 sensor!");
    delay(500);
    return;
  }

  // Normalize RGB values by dividing with clear channel and scaling to [0,1]
  float total = r + g + b;
  if (total == 0) {
    Serial.println("No color detected");
    delay(500);
    return;
  }
  input[0] = static_cast<float>(r) / total; // Red
  input[1] = static_cast<float>(g) / total; // Green
  input[2] = static_cast<float>(b) / total; // Blue

  // Run the inference
  if (interpreter.Invoke() != kTfLiteOk) {
    TF_LITE_REPORT_ERROR(error_reporter, "Invoke failed");
    return;
  }

  // Get the output class index
