tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Declare global model pointer
const tflite::Model* model = nullptr;

// Declare operator resolver and interpreter
tflite::ops::micro::AllOpsResolver resolver;
tflite::MicroInterpreter interpreter(model, resolver, tensor_arena, TENSOR_ARENA_SIZE, error_reporter);

// Create an input tensor handle
TfLiteTensor* input = nullptr;

// Initialize the APDS9960 sensor
Adafruit_APDS9960 apds;

void setup() {
  // Start serial communication for debugging/output
  Serial.begin(9600);

  // Initialize the APDS-9960 sensor
  if (!apds.init()) {
    Serial.println("Failed to initialize APDS-9960 sensor!");
    while (1) delay(10); // Stay here forever
  }

  Serial.println("APDS-9960 initialized!");
  apds.enableColor(true);

  // Load the model from flash memory into an array of bytes.
  model = tflite::GetModel(g_model);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    error_reporter->Report("Model schema version not supported\n");
    while (1) delay(10); // Stay here forever
  }

  // Build the interpreter with the model, allocator, and resolver.
  interpreter.AllocateTensors();

  // Assign the model input tensor to a pointer
  input = interpreter.input(0);
}

void loop() {
  // Initialize variables for color readings
  uint16_t r, g, b, c;

  // Read the color values from the sensor
  if (apds.colorRead(&r, &g, &b, &c)) {
    // Normalize the color values to a range of 0.0 to 1.0 based on max value
    float max_val = std::max(std::max(r, g), b);
    r = constrain(r, 0, max_val);
    g = constrain(g, 0, max_val);
    b = constrain(b, 0, max_val);

    float normalized_r = static_cast<float>(r) / max_val;
    float normalized_g = static_cast<float>(g) / max_val;
    float normalized_b = static_cast<float>(b) / max_val;

    // Assign the color values to the input tensor
    input->data.f[0] = normalized_r;
    input->data.f[1] = normalized_g;
    input->data.f[2] = normalized_b;

    // Run inference on the model
    if (interpreter.Invoke() != kTfLiteOk) {
      error_reporter->Report("Invoke failed\n");
      return;
    }

    // Retrieve the classification result from the output tensor
    TfLiteTensor* output = interpreter.output(0);
    uint8_t predicted_class = static_cast<uint8_t>(output->data.uint8[0]);

    // Map the predicted class to an emoji and print it
    switch (predicted_class) {
      case 0:
        Serial.println("Apple \uF8FF");  // Unicode for Apple Emoji
        break;
      case 1:
        Serial.println("Banana \U0001F34C");  // Unicode for Banana Emoji
        break;
      case 2:
        Serial.println("Orange \U0001F34A");  // Unicode for Orange Emoji
        break;
      default:
        Serial.println("Unknown object");
        break;
    }
  }

  delay(500);  // Delay before the next reading
}
