#include <Wire.h>
#include <TensorFlowLite.h>
#include "tensorflow/lite/micro/all_ops_resolver.h"
#include "tensorflow/lite/micro/micro_error_reporter.h"
#include "tensorflow/lite/micro/micro_interpreter.h"
#include "tensorflow/lite/schema/schema_generated.h"
#include "Adafruit_APDS9960.h"

// Model includes
#include "model.h"  // This should contain the flatbuffer model

// Define tensor arena size
constexpr int kTensorArenaSize = 6000;
uint8_t tensor_arena[kTensorArenaSize];

// TensorFlow Lite objects
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  TF_LITE_REPORT_ERROR(error_reporter,
                       "Model provided is schema version %d not equal "
                       "to supported version %d.",
                       model->version(), TFLITE_SCHEMA_VERSION);
  return;
}

tflite::ops::micro::AllOpsResolver resolver;

// Create an interpreter to run the model with micro_error_reporter
tflite::MicroInterpreter interpreter(model, resolver, tensor_arena,
                                      kTensorArenaSize, error_reporter);

// Allocate memory from the tensor_arena for the model's tensors.
TfLiteStatus allocate_status = interpreter.AllocateTensors();
if (allocate_status != kTfLiteOk) {
  TF_LITE_REPORT_ERROR(error_reporter, "AllocateTensors() failed");
  return;
}

// Ensure input is float32 and has 3 dimensions
TfLiteTensor* input = interpreter.input(0);
if ((input->type != kTfLiteFloat32) || (input->dims->size != 1)) {
  TF_LITE_REPORT_ERROR(error_reporter, "Bad input tensor parameters in model");
  return;
}

// Ensure output is uint8 and has 1 dimension
TfLiteTensor* output = interpreter.output(0);
if ((output->type != kTfLiteUInt8) || (output->dims->size != 1)) {
  TF_LITE_REPORT_ERROR(error_reporter, "Bad output tensor parameters in model");
  return;
}

// Sensor initialization
Adafruit_APDS9960 apds;

void setup() {
  Serial.begin(9600);

  // Initialize APDS-9960 (configure I2C and initial values)
  if (!apds.init()) {
    Serial.println("Failed to initialize APDS-9960!");
    while (1);
  }
  apds.enableColor(true);
}

void loop() {
  uint16_t r, g, b, c;

  // Check if data is ready
  if (apds.colorDataReady()) {
    apds.getColorData(&r, &g, &b, &c);

    // Normalize RGB values to [0, 1]
    float total = r + g + b;
    float red = static_cast<float>(r) / total;
    float green = static_cast<float>(g) / total;
    float blue = static_cast<float>(b) / total;

    // Write normalized color values to input tensor
    input->data.f[0] = red;
    input->data.f[1] = green;
    input->data.f[2] = blue;

    // Run the inference
    TfLiteStatus invoke_status = interpreter.Invoke();
    if (invoke_status != kTfLiteOk) {
      TF_LITE_REPORT_ERROR(error_reporter, "Invoke failed");
      return;
    }

    // Read the predicted class from output tensor
    uint8_t predicted_class = output->data.uint8[0];

    // Map predicted class to emojis and print
    switch (predicted_class) {
      case 0:
        Serial.println("Apple \uF8FF");  // Apple emoji
        break;
      case 1:
        Serial.println("Banana \U0001F34C");  // Banana emoji
        break;
      case 2:
        Serial.println("Orange \U0001F34A");  // Orange emoji
        break;
      default:
        Serial.println("Unknown");
    }
  }

  delay(500);
}
