    Serial.println("Bad input tensor parameters.");
    while (1);
  }
}

void loop() {
  uint16_t r, g, b, c;

  // Read color data from APDS-9960
  if (!apds.colorData(&r, &g, &b)) {
    Serial.println("Failed to read color data.");
    return;
  }

  // Normalize color values to float [0.0, 1.0]
  float red = r / 65535.0f;
  float green = g / 65535.0f;
  float blue = b / 65535.0f;

  // Copy normalized color values to input tensor
  input->data.f[0] = red;
  input->data.f[1] = green;
  input->data.f[2] = blue;

  // Run the inference
  if (interpreter.Invoke() != kTfLiteOk) {
    Serial.println("Inference failed.");
    return;
  }

  // Get output tensor
  TfLiteTensor* output = interpreter.output(0);

  // Read classification result
  uint8_t class_index = output->data.uint8[0];

  // Print the result with Unicode emojis
  switch (class_index) {
    case 0:
      Serial.println("Apple \xF0\x9F\x8D\x8E");
