#include <TensorFlowLite.h>
#include <Wire.h>
#include <Adafruit_APDS9960.h>
#include "model.h"

// Declare TensorFlow Lite Micro components
tflite::ErrorReporter error_reporter;
const tflite::Model* model = tflite::GetModel(g_model);
tflite::MicroInterpreter interpreter(model, tflite::ops::micro::AllOpsResolver(), tensor_arena, sizeof(tensor_arena), &error_reporter);

// Define tensor arena
uint8_t tensor_arena[6000];

// APDS9960 RGB sensor
Adafruit_APDS9960 apds;

// Input tensor buffer
float* input = interpreter.input(0)->data.f;
const tflite::Model* model_ptr = nullptr;
tflite::Interpreter* interpreter_ptr = &interpreter;

void setup() {
  // Initialize Serial communication
  Serial.begin(9600);

  // Initialize APDS-9960 (RGB Sensor)
  if (!apds.init()) {
    Serial.println("Failed to initialize APDS-9960 sensor!");
    while (1);
  }
  apds.enableColor(true);

  // Load the model and allocate memory
  TfLiteStatus allocate_status = interpreter.AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    error_reporter.Report("AllocateTensors() failed");
    return;
  }

  Serial.println("Setup complete. Ready to classify objects.");
}

void loop() {
  uint16_t r, g, b, c;
  apds.getColorData(&r, &g, &b, &c);

  // Normalize RGB values
  float sum = r + g + b;
  input[0] = static_cast<float>(r) / sum; // Red
  input[1] = static_cast<float>(g) / sum; // Green
  input[2] = static_cast<float>(b) / sum; // Blue

  // Run inference
  TfLiteStatus invoke_status = interpreter.Invoke();
  if (invoke_status != kTfLiteOk) {
    error_reporter.Report("Invoke failed");
    return;
  }

  // Process output
  uint8_t* output = interpreter.output(0)->data.uint8;
  String object_class;

  switch (*output) {
    case 0:
      object_class = "Apple \xF0\x9F\x8D\x8E"; // Apple emoji
      break;
    case 1:
      object_class = "Banana \xF0\x9F\x8C\xAA"; // Banana emoji
      break;
    case 2:
      object_class = "Orange \xF0\x9F\x8C\x85"; // Orange emoji
      break;
    default:
      object_class = "Unknown";
      break;
  }

  // Print result
  Serial.println("Detected: " + object_class);

  delay(1000); // Wait for a second before next reading
}
