#include <Wire.h>
#include <Adafruit_APDS9960.h>
#include "tensorflow/lite/micro/all_ops_resolver.h"
#include "tensorflow/lite/micro/micro_error_reporter.h"
#include "tensorflow/lite/micro/micro_interpreter.h"
#include "tensorflow/lite/schema/schema_generated.h"
#include "model.h"  // This should be generated from your TensorFlow Lite model

// Define the size of the tensor arena (RAM) used for inference
constexpr int kTensorArenaSize = 6000;
uint8_t tensor_arena[kTensorArenaSize];

// Error reporter for logging errors
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Declare the model, interpreter and resolver
const tflite::Model* model = nullptr;
tflite::MicroInterpreter* interpreter = nullptr;
tflite::AllOpsResolver resolver;

// Define RGB sensor object
Adafruit_APDS9960 apds;

// Input tensor index
int input_tensor_index = 0;

void setup() {
  Serial.begin(9600);

  // Initialize the APDS-9960 (configure I2C and initial values)
  if (!apds.begin()) {
    error_reporter->Report("Error initializing APDS-9960 sensor");
    while (1);
  }

  apds.enableColor(true);  // Enable color sensing
  delay(50);

  // Load the model from flash memory into a data structure in RAM
  model = tflite::GetModel(g_model);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    error_reporter->Report("Model schema version does not match expected version");
    while (1);
  }

  // Instantiate the interpreter
  static tflite::MicroInterpreter static_interpreter(
      model, resolver, tensor_arena, kTensorArenaSize, error_reporter);
  interpreter = &static_interpreter;

  // Allocate memory from the tensor arena for the model's tensors.
  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    error_reporter->Report("AllocateTensors() failed");
    while (1);
  }

  // Get a pointer to the input tensor
  input_tensor_index = interpreter->inputs()[0];
}

void loop() {
  delay(250);  // Sample every 250 milliseconds

  uint16_t r, g, b, c;
  apds.getColorData(&r, &g, &b, &c);

  // Normalize the color values to be between 0 and 1
  float red = (float)r / 4095.0f;
  float green = (float)g / 4095.0f;
  float blue = (float)b / 4095.0f;

  // Get a pointer to the input tensor and fill it with RGB values
  float* input = interpreter->typed_input_tensor<float>(input_tensor_index);
  input[0] = red;
  input[1] = green;
  input[2] = blue;

  // Run inference on the model using the input data
  TfLiteStatus invoke_status = interpreter->Invoke();
  if (invoke_status != kTfLiteOk) {
    error_reporter->Report("Invoke failed");
    return;
  }

  // Get a pointer to the output tensor and print results
  uint8_t* output = interpreter->typed_output_tensor<uint8_t>(0);

  switch (output[0]) {
    case 0:
      Serial.println("Apple \uF8FF");  // Unicode for an apple emoji
      break;
    case 1:
      Serial.println("Banana \uD83C\uDF4C");  // Unicode for a banana emoji
      break;
    case 2:
      Serial.println("Orange \uD83C\uDF4A");  // Unicode for an orange emoji
      break;
    default:
      Serial.println("Unknown object");
      break;
  }
}
