```cpp
#include <Wire.h>
#include <Adafruit_APDS9960.h>
#include "TensorFlowLite.h"
#include "tensorflow/lite/micro/all_ops_resolver.h"
#include "tensorflow/lite/micro/micro_error_reporter.h"
#include "tensorflow/lite/micro/micro_interpreter.h"
#include "model.h"

// Define the size of the tensor arena (memory area for input, output and intermediate arrays)
const int tensor_arena_size = 6000;
uint8_t tensor_arena[tensor_arena_size];

// Create an error reporter object
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Load the model from the flash
const tflite::Model* model = tflite::GetModel(model);

// Resolve all operators in the model
tflite::ops::micro::AllOpsResolver resolver;

// Build an interpreter to run the model with the op resolver and memory planner.
tflite::MicroInterpreter interpreter(model, resolver, tensor_arena, tensor_arena_size, error_reporter);

// Allocate memory from the tensor arena for the model's tensors.
TfLiteStatus allocate_status = interpreter.AllocateTensors();
if (allocate_status != kTfLiteOk) {
  error_reporter->Report("AllocateTensors() failed\n");
}

// Ensure the input tensor is a float32
TfLiteTensor* input = interpreter.input(0);
if (input->type != kTfLiteFloat32) {
  error_reporter->Report("Input tensor must be float32\n");
}

// Initialize the sensor
Adafruit_APDS9960 apds;

void setup() {
  Serial.begin(9600);

  // Initialize APDS-9960 (configure I2C and interrupts)
  if (!apds.init()) {
    Serial.println("Failed to initialize APDS-9960! Check your wiring.");
    while (1);
  }
  apds.enableColor(true);
}

void loop() {
  uint16_t r, g, b, c;

  // Read the color data
  if (!apds.colorAvailable()) {
    delay(50);
    return;
  }

  apds.getColorData(&r, &g, &b, &c);

  // Normalize RGB values to [0, 1]
  float red = static_cast<float>(r) / c;
  float green = static_cast<float>(g) / c;
  float blue = static_cast<float>(b) / c;

  // Copy normalized color data into input tensor
  input->data.f[0] = red;
  input->data.f[1] = green;
  input->data.f[2] = blue;

  // Run the inference
  TfLiteStatus invoke_status = interpreter.Invoke();
  if (invoke_status != kTfLiteOk) {
    error_reporter->Report("Invoke failed\n");
  }

  // Process the output tensor
  TfLiteTensor* output = interpreter.output(0);
  uint8_t predicted_class = output->data.uint8[0];

  // Print the result to Serial
  switch (predicted_class) {
    case 0:
      Serial.println("Apple \uF8FF"); // Apple emoji
      break;
    case 1:
      Serial.println("Banana \U0001F34C"); // Banana emoji
      break;
    case 2:
      Serial.println("Orange \U0001F34A"); // Orange emoji
      break;
    default:
      Serial.println("Unknown");
      break;
  }

  delay(500); // Delay between readings
}
```

