```cpp
#include <TensorFlowLite.h>
#include <tensorflow/lite/micro/all_ops_resolver.h>
#include <tensorflow/lite/micro/micro_error_reporter.h>
#include <tensorflow/lite/micro/micro_interpreter.h>
#include <Adafruit_APDS9960.h>

#include "model.h"

// Define the error reporter
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Create an instance of the model
const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  error_reporter->Report("Model schema version does not match\nExpected %d found %d\n", TFLITE_SCHEMA_VERSION, model->version());
}

// Define the operator resolver
tflite::ops::micro::AllOpsResolver resolver;

// Create an interpreter to run the model with MicroArenaBufferAllocator.
const int tensor_arena_size = 2048;
uint8_t tensor_arena[tensor_arena_size];
tflite::MicroInterpreter interpreter(model, resolver, tensor_arena, tensor_arena_size, error_reporter);

// Allocate memory from the tensor arena for the model's tensors
TfLiteStatus allocate_status = interpreter.AllocateTensors();
if (allocate_status != kTfLiteOk) {
  error_reporter->Report("AllocateTensors() failed\n");
}

// Input tensor
float* input = interpreter.input(0)->data.f;

// Output tensor
uint8_t* output = interpreter.output(0)->data.uint8;

// Initialize the APDS9960 sensor
Adafruit_APDS9960 apds;
void setup() {
  Serial.begin(9600);

  if (!apds.begin()) {
    error_reporter->Report("Failed to initialize APDS9960 sensor!\n");
    while (1);
  }

  // Configure the sensor
  apds.enableColor(true);
}

// Main loop function
void loop() {
  uint16_t r, g, b, c;
  if (!apds.colorGetRawData(&r, &g, &b, &c)) {
    error_reporter->Report("Failed to get color data from sensor!\n");
    delay(500);
    return;
  }

  // Convert raw data to normalized values
  float total = r + g + b;
  input[0] = r / total; // Red
  input[1] = g / total; // Green
  input[2] = b / total; // Blue

  // Run inference
  TfLiteStatus invoke_status = interpreter.Invoke();
  if (invoke_status != kTfLiteOk) {
    error_reporter->Report("Invoke failed\n");
    return;
  }

  // Process output and map to class labels
  const char* classes[] = {"Apple", "Banana", "Orange"};
  uint8_t predicted_class = *output;

  if (predicted_class < sizeof(classes) / sizeof(classes[0])) {
    Serial.print("Detected: ");
    Serial.println(classes[predicted_class]);

    // Output Unicode emojis
    switch(predicted_class) {
      case 0: // Apple
        Serial.write((uint8_t*)"\xF0\x9F\x8D\x8E", 4); // 🍎
        break;
      case 1: // Banana
        Serial.write((uint8_t*)"\xF0\x9F\x8C\x8A", 4); // 🍌
        break;
      case 2: // Orange
        Serial.write((uint8_t*)"\xF0\x9F\x8D\x85", 4); // 🍉 (Using watermelon as placeholder, no direct emoji for orange)
        break;
    }
    Serial.println();
  }

  delay(1000);
}
