#include <Arduino.h>
#include <TensorFlowLite.h>
#include "tensorflow/lite/micro/all_ops_resolver.h"
#include "tensorflow/lite/micro/micro_error_reporter.h"
#include "tensorflow/lite/micro/micro_interpreter.h"
#include "tensorflow/lite/schema/schema_generated.h"
#include "tensorflow/lite/version.h"
#include "Adafruit_APDS9960.h"

// Define the model path and tensor arena size
#define TENSOR_ARENA_SIZE (2 * 1024)

// Include the trained model header file
#include "model.h"

// Declare a global error reporter object
tflite::ErrorReporter* error_reporter = nullptr;

// Create an area of memory to use for input, output, and intermediate arrays.
uint8_t tensor_arena[TENSOR_ARENA_SIZE];

// Declare global variables
const tflite::Model* model = nullptr;
tflite::MicroInterpreter* interpreter = nullptr;
TfLiteTensor* input = nullptr;
TfLiteTensor* output = nullptr;

// Create an instance of the sensor
Adafruit_APDS9960 apds;

void setup() {
  // Initialize serial communication
  Serial.begin(9600);

  // Set up logging
  static tflite::MicroErrorReporter micro_error_reporter;
  error_reporter = &micro_error_reporter;

  // Map the model into a usable data structure
  model = tflite::GetModel(g_model);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Model schema version not supported");
    return;
  }

  // Create an AllOpsResolver object. This one works with every TensorFlow Lite operator,
  // but has a larger binary size and takes longer to initialize.
  static tflite::AllOpsResolver resolver;

  // Build an interpreter to run the model
  static tflite::MicroInterpreter static_interpreter(model, resolver, tensor_arena, TENSOR_ARENA_SIZE, error_reporter);
  interpreter = &static_interpreter;

  // Allocate memory from the tensor_arena for the model's tensors.
  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    Serial.println("AllocateTensors() failed");
    return;
  }

  // Get pointers to the model's input and output tensors
  input = interpreter->input(0);
  output = interpreter->output(0);

  // Initialize the sensor
  if (!apds.begin()) {
    Serial.println("Failed to initialize APDS9960 sensor!");
    while (1);
  }

  apds.enableColor(true);
}

void loop() {
  uint16_t r, g, b, c;

  // Check if color data is ready to be read
  if (apds.colorDataReady()) {
    apds.getColorData(&r, &g, &b, &c);

    // Normalize the values to a range of [0.0, 1.0]
    float red = r / static_cast<float>(c);
    float green = g / static_cast<float>(c);
    float blue = b / static_cast<float>(c);

    // Copy normalized RGB values into the model's input tensor
