#include "model.h"
#include <Adafruit_APDS9960.h>

// Define the tensor arena size
#define TENSOR_ARENA_SIZE (2 * 1024)

// Create a buffer for the tensor arena
uint8_t tensor_arena[TENSOR_ARENA_SIZE];

// Create an error reporter instance
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Declare pointers to model and interpreter
const tflite::Model* model = nullptr;
tflite::MicroInterpreter* interpreter = nullptr;

// Create an operator resolver instance
tflite::AllOpsResolver resolver;

// Define the input tensor buffer
float input_data[3] = {0.0f, 0.0f, 0.0f};

// Initialize the APDS9960 sensor
Adafruit_APDS9960 apds;

void setup() {
  // Start serial communication for debugging
  Serial.begin(9600);

  // Initialize the APDS9960 sensor
  if (!apds.begin()) {
    Serial.println("Failed to initialize APDS9960!");
    while (1);
  }
  apds.enableColor(true);

  // Load and validate the model
  model = tflite::GetModel(model_data);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Model schema version not supported");
    return;
  }

  // Instantiate the interpreter
  interpreter = new tflite::MicroInterpreter(
      model, resolver, tensor_arena, TENSOR_ARENA_SIZE, error_reporter);

  // Allocate memory for tensors
  if (interpreter->AllocateTensors() != kTfLiteOk) {
    Serial.println("Failed to allocate tensors!");
    return;
  }

  // Get pointers to the input and output tensors
  TfLiteTensor* input = interpreter->input(0);
  if ((input->type != kTfLiteFloat32) || (input->bytes / sizeof(float) != 3)) {
    Serial.println("Bad input tensor parameters in model");
    return;
  }
}

void loop() {
  // Read the color values from the APDS9960 sensor
  uint16_t r, g, b, c;
  apds.getColorData(&r, &g, &b, &c);

  // Normalize the color values to a range between 0 and 1
  float sum = r + g + b + c;
  input_data[0] = static_cast<float>(r) / sum; // Red
  input_data[1] = static_cast<float>(g) / sum; // Green
  input_data[2] = static_cast<float>(b) / sum; // Blue

  // Copy the normalized color values into the input tensor
  float* input = interpreter->input(0)->data.f;
  for (int i = 0; i < 3; i++) {
    input[i] = input_data[i];
  }

  // Run inference
  if (interpreter->Invoke() != kTfLiteOk) {
    Serial.println("Inference failed!");
    return;
  }

  // Get the output tensor and process the result
  TfLiteTensor* output = interpreter->output(0);
  uint8_t predicted_class = output->data.uint8[0];

  // Map the predicted class to a human-readable label
  const char* labels[] = {"Apple", "Banana", "Orange"};
  if (predicted_class < sizeof(labels) / sizeof(labels[0])) {
    Serial.print("Detected: ");
    Serial.println(labels[predicted_class]);
  } else {
    Serial.println("Unknown class");
  }

  // Delay for a short period before the next reading
  delay(1000);
}
