#include "model.h"

// Define the error reporter and other necessary variables
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  error_reporter->Report("Model schema version does not match");
}

// Define the tensor arena
#define TENSOR_ARENA_SIZE (1024)
uint8_t tensor_arena[TENSOR_ARENA_SIZE];

// Instantiate the interpreter and allocate memory
tflite::MicroInterpreter* interpreter = nullptr;
tflite::AllOpsResolver resolver;

interpreter = new tflite::MicroInterpreter(model, resolver, tensor_arena, TENSOR_ARENA_SIZE, error_reporter);
tflite::Interpreter::AllocateTensorsStatus allocate_status = interpreter->AllocateTensors();
if (allocate_status != kTfLiteOk) {
  error_reporter->Report("AllocateTensors() failed");
}

// Retrieve input tensor details
tflite::Tensor* input_tensor = interpreter->input(0);
if ((input_tensor == nullptr) || (input_tensor->dims->size != 1) || (input_tensor->dims->data[0] != 3)) {
  error_reporter->Report("Bad input tensor parameters in model");
}

// Initialize the APDS9960 RGB sensor
Adafruit_APDS9960 apds;

void setup() {
  // Start serial communication for debugging/output
  Serial.begin(9600);

  // Initialize and configure the APDS9960 sensor
  if (!apds.begin()) {
    error_reporter->Report("APDS-9960 not found");
    while (1);
  }

  apds.enableColor(true);
}

void loop() {
  uint16_t r, g, b, c;

  // Read the color data from the sensor
  if (!apds.colorAvailable()) {
    delay(50);
    return;
  }

  apds.getColorData(&r, &g, &b, &c);

  // Normalize the RGB values to [0, 1] range (assuming 16-bit readings)
  float red = r / 65535.0f;
  float green = g / 65535.0f;
  float blue = b / 65535.0f;

  // Copy the normalized RGB values to the model input tensor
  float* input = input_tensor->data.f;
  input[0] = red;
  input[1] = green;
  input[2] = blue;

  // Run the inference
  if (interpreter->Invoke() != kTfLiteOk) {
    error_reporter->Report("Invoke failed on TensorFlow Lite interpreter");
    return;
  }

  // Process the output tensor
  tflite::Tensor* output_tensor = interpreter->output(0);
  uint8_t predicted_class = output_tensor->data.uint8[0];

  // Map the class index to a Unicode emoji and print it
  const char* emoji;
  switch (predicted_class) {
    case 0: emoji = "🍎"; break;  // Apple
    case 1: emoji = "🍌"; break;  // Banana
    case 2: emoji = "🍊"; break;  // Orange
    default: emoji = "?"; break;
  }

  Serial.println(emoji);

  delay(1000);  // Wait for a second before the next inference
}
