#include "tensorflow/lite/micro/micro_error_reporter.h"
#include "tensorflow/lite/micro/micro_interpreter.h"
#include "tensorflow/lite/schema/schema_generated.h"
#include "model.h"  // This is your model header file

// Define the buffer size for the tensor arena
const int kTensorArenaSize = 1024;
uint8_t tensor_arena[kTensorArenaSize];

// Create an error reporter to log messages
tflite::MicroErrorReporter micro_error_reporter;

// Declare global variables
Adafruit_APDS9960 apds;
const tflite::Model* model = nullptr;
tflite::ops::micro::AllOpsResolver resolver;
tflite::MicroInterpreter interpreter(model, resolver, tensor_arena, kTensorArenaSize, &micro_error_reporter);
TfLiteTensor* input_tensor;
TfLiteTensor* output_tensor;

// Initialize the sensor
void setupSensor() {
  if (!apds.begin()) {
    Serial.println("No APDS9960 found!");
    while (1) { delay(1000); }
  }

  apds.enableColor(true);
}

// Load and initialize the TensorFlow Lite model
bool loadModel() {
  // Map the model into a usable data structure. This doesn't involve actually parsing or processing it.
  model = tflite::GetModel(g_model);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Error: Model schema version does not match");
    return false;
  }

  // Build the interpreter
  if (interpreter.AllocateTensors() != kTfLiteOk) {
    Serial.println("AllocateTensors() failed");
    return false;
  }

  // Get pointers to input and output tensors.
  input_tensor = interpreter.input(0);
  output_tensor = interpreter.output(0);

  return true;
}

void setup() {
  Serial.begin(9600);
  setupSensor();

  if (!loadModel()) {
    Serial.println("Failed to load model");
    while (1) { delay(1000); }
  }
}

void loop() {
  uint16_t r, g, b, c;

  // Read color data from sensor
  apds.getColorData(&r, &g, &b, &c);

  // Normalize the RGB values to a range between 0 and 1
  float red = static_cast<float>(r) / 1023.0f;
  float green = static_cast<float>(g) / 1023.0f;
  float blue = static_cast<float>(b) / 1023.0f;

  // Fill the input tensor
  float* input_ptr = input_tensor->data.f;
  input_ptr[0] = red;
  input_ptr[1] = green;
  input_ptr[2] = blue;

  // Run inference on the model
  if (interpreter.Invoke() != kTfLiteOk) {
    Serial.println("Invoke failed");
    return;
  }

  // Process the output tensor
  uint8_t predicted_class = *output_tensor->data.uint8;

  // Map the predicted class to a Unicode emoji and print it over Serial
  switch (predicted_class) {
    case 0:
      Serial.println("🍎");  // Apple
      break;
    case 1:
      Serial.println("🍌");  // Banana
      break;
    case 2:
      Serial.println("🍊");  // Orange
      break;
    default:
      Serial.println("Unknown");
      break;
  }

  delay(500);  // Delay between readings
}
