TfLiteStatus allocate_status = interpreter->AllocateTensors();
if (allocate_status != kTfLiteOk) {
  error_reporter->Report("AllocateTensors() failed\n");
  return;
}

// Obtain pointers to the model's input and output tensors.
TfLiteTensor* input = interpreter->input(0);
TfLiteTensor* output = interpreter->output(0);

// Initialize the APDS9960 sensor
Adafruit_APDS9960 apds;

void setup() {
  // Start serial communication for debugging purposes
  Serial.begin(9600);

  // Initialize the APDS-9960 (configure I2C and initial values)
  if (!apds.init()) {
    Serial.println("Failed to initialize device! Please check your wiring.");
    while (1);
  }

  // Start running the APDS-9960 light sensor (no waiting for data)
  apds.enableColor(true);
}

void loop() {
  uint16_t r, g, b, c;

  if (!apds.colorAvailable()) {
    delay(50);
    return;
  }

  // Read the color values
  apds.getColorData(&r, &g, &b, &c);

  // Normalize RGB values to [0.0, 1.0] range
  float sum = r + g + b;
  if (sum > 0) {
    input->data.f[0] = r / sum;  // Red
    input->data.f[1] = g / sum;  // Green
    input->data.f[2] = b / sum;  // Blue
  } else {
    input->data.f[0] = 0.0f;
    input->data.f[1] = 0.0f;
    input->data.f[2] = 0.0f;
  }

  // Run the inference
  TfLiteStatus invoke_status = interpreter->Invoke();
  if (invoke_status != kTfLiteOk) {
    error_reporter->Report("Invoke failed\n");
    return;
  }

  // Process the output tensor to get the classification result
  int predicted_class = output->data.uint8[0];

  // Map the class index to a Unicode emoji and print it
  switch (predicted_class) {
    case 0:
      Serial.println("🍎");  // Apple
      break;
    case 1:
      Serial.println("🍌");  // Banana
      break;
    case 2:
      Serial.println("🍊");  // Orange
      break;
    default:
      Serial.println("Unknown");
      break;
  }

  delay(1000);  // Wait for a second before the next reading
}
