// a large buffer ahead of time, we allocate each part separately.
const tflite::Interpreter::TfLiteAllocationParams allocation_params;
tflite::AllOpsResolver resolver;

// Build an interpreter to run the model with micro_interpreter
tflite::MicroInterpreter interpreter(model, resolver, tensor_arena,
                                      kTensorArenaSize, error_reporter);

// Create an instance of the sensor
Adafruit_APDS9960 apds = Adafruit_APDS9960();

void setup() {
  Serial.begin(9600);

  // Initialize APDS-9960 (configure I2C and initial values)
  if (!apds.begin()) {
    Serial.println("Error initializing APDS-9960");
    while (1);
  }

  // Enable color sensing module
  apds.enableColor(true);

  // Allocate memory for tensors
  interpreter.AllocateTensors();
}

void loop() {
  // Check if new color data is available
  if (apds.colorDataReady()) {
    uint16_t r, g, b, c;
    apds.getColorData(&r, &g, &b, &c);

    // Normalize RGB values to [0.0, 1.0]
    float normalized_r = static_cast<float>(r) / 4095.0f;
    float normalized_g = static_cast<float>(g) / 4095.0f;
    float normalized_b = static_cast<float>(b) / 4095.0f;

    // Get a pointer to the input tensor
    TfLiteTensor* input = interpreter.input(0);

    // Copy normalized RGB values to the input tensor
    input->data.f[0] = normalized_r;
    input->data.f[1] = normalized_g;
    input->data.f[2] = normalized_b;

    // Run the inference
    if (interpreter.Invoke() != kTfLiteOk) {
      error_reporter->Report("Invoke failed.\n");
    }

    // Get a pointer to the output tensor
    TfLiteTensor* output = interpreter.output(0);

    // Process the result from the output tensor
    uint8_t predicted_class = output->data.uint8[0];

    // Print the Unicode emoji based on the predicted class
    switch (predicted_class) {
      case 0:
        Serial.println("🍎");  // Apple
        break;
      case 1:
        Serial.println("🍌");  // Banana
        break;
      case 2:
        Serial.println("🍊");  // Orange
        break;
      default:
        Serial.println("Unknown");
    }
  }

  delay(500);  // Delay for a bit before the next loop iteration
}
