if (allocate_status != kTfLiteOk) {
  error_reporter->Report("AllocateTensors() failed\n");
}

// Define model inputs
TfLiteTensor* input = interpreter.input(0);
if ((input->type != kTfLiteFloat32) || (input->bytes / sizeof(float) != 3)) {
  error_reporter->Report("Bad input tensor parameters in model\n");
}

// Initialize the APDS9960 color sensor
Adafruit_APDS9960 apds;

void setup() {
  Serial.begin(9600);

  // Initialize sensor
  if (!apds.begin()) {
    Serial.println("No APDS-9960 found");
    while (1);
  }
  apds.enableColor(true);
}

void loop() {
  // Get color data from the sensor
  uint16_t r, g, b, c;
  apds.getColorData(&r, &g, &b, &c);

  // Normalize RGB values to [0.0, 1.0]
  float red = static_cast<float>(r) / 1023.0f;
  float green = static_cast<float>(g) / 1023.0f;
  float blue = static_cast<float>(b) / 1023.0f;

  // Copy data to input tensor
  input->data.f[0] = red;
  input->data.f[1] = green;
  input->data.f[2] = blue;

  // Run the inference
  TfLiteStatus invoke_status = interpreter.Invoke();
  if (invoke_status != kTfLiteOk) {
    error_reporter->Report("Invoke failed\n");
  }

  // Get output tensor and process result
  TfLiteTensor* output = interpreter.output(0);
  uint8_t predicted_class = output->data.uint8[0];

  // Map the prediction to an emoji and print it
  const char* object_emoji;
  switch (predicted_class) {
    case 0:
      object_emoji = "\xF0\x9F\x8D\x8E"; // Apple 🍎
      break;
    case 1:
      object_emoji = "\xF0\x9F\x8C\x8A"; // Banana 🍌
      break;
    case 2:
      object_emoji = "\xF0\x9F\x8D\x85"; // Orange 🍊
      break;
    default:
      object_emoji = "?";
      break;
  }

  Serial.print("Predicted Object: ");
  Serial.println(object_emoji);

  delay(1000); // Delay between readings
}
