#include <Arduino.h>
#include <Wire.h>
#include <Adafruit_APDS9960.h>
#include "tensorflow/lite/micro/all_ops_resolver.h"
#include "tensorflow/lite/micro/micro_error_reporter.h"
#include "tensorflow/lite/micro/micro_interpreter.h"
#include "tensorflow/lite/schema/schema_generated.h"
#include "model.h"  // Ensure this path is correct

// Define the APDS9960 sensor
Adafruit_APDS9960 apds;

// Tensor arena size
constexpr int kTensorArenaSize = 2048;
uint8_t tensor_arena[kTensorArenaSize];

// TensorFlow Lite Micro components
tflite::ErrorReporter* error_reporter = new tflite::MicroErrorReporter();
const tflite::Model* model = tflite::GetModel(g_model);
tflite::ops::micro::AllOpsResolver resolver;
tflite::MicroInterpreter interpreter(model, resolver, tensor_arena, kTensorArenaSize, error_reporter);

// Input and output tensors
TfLiteTensor* input_tensor;
TfLiteTensor* output_tensor;

void setup() {
  // Start serial communication for debugging
  Serial.begin(9600);

  // Initialize APDS9960 sensor
  if (!apds.begin()) {
    Serial.println("Failed to initialize APDS9960");
    while (1);
  }
  apds.enableColor(true);
  delay(250);  // Let the sensor initialize

  // Load and verify the model
  TF_LITE_REPORT_ERROR(error_reporter, "Model loaded: %s", model->version());

  // Allocate memory for tensors
  interpreter.AllocateTensors();

  // Get pointers to input and output tensors
  input_tensor = interpreter.input(0);
  output_tensor = interpreter.output(0);

  // Ensure the model is ready
  if ((input_tensor == nullptr) || (output_tensor == nullptr)) {
    TF_LITE_REPORT_ERROR(error_reporter, "Failed to allocate tensors!");
    while (1);
  }

  Serial.println("Setup complete.");
}

void loop() {
  // Read color data from APDS9960
  uint16_t r, g, b;
  if (!apds.colorGetRGB(&r, &g, &b)) {
    Serial.println("Failed to read color data");
    return;
  }

  // Normalize the RGB values to [0.0, 1.0]
  float red = static_cast<float>(r) / 65535.0f;
  float green = static_cast<float>(g) / 65535.0f;
  float blue = static_cast<float>(b) / 65535.0f;

  // Set the input tensor values
  input_tensor->data.f[0] = red;
  input_tensor->data.f[1] = green;
  input_tensor->data.f[2] = blue;

  // Run inference
  interpreter.Invoke();

  // Get the output tensor value
  int predicted_class = static_cast<int>(output_tensor->data.uint8[0]);

  // Map the predicted class to a Unicode emoji
  const char* object_emoji;
  switch (predicted_class) {
    case 0:
      object_emoji = "🍎";  // Apple
      break;
    case 1:
      object_emoji = "🍌";  // Banana
      break;
    case 2:
      object_emoji = "🍊";  // Orange
      break;
    default:
      object_emoji = "❓";  // Unknown
      break;
  }

  // Print the result to Serial
  Serial.print("Predicted Object: ");
  Serial.println(object_emoji);

  // Delay before next reading
  delay(1000);
}
```

### Key Points:
- **Include Necessary Libraries**: Ensure all required libraries are included at the beginning.
- **Define Tensor Arena**: Allocate a tensor arena with sufficient size.
- **Load and Verify Model**: Load the model from `model.h` and verify it.
- **Allocate Memory**: Allocate memory for tensors using `interpreter.AllocateTensors()`.
- **Set Up Sensors**: Initialize the APDS9960 sensor for color readings.
- **Normalize Data**: Normalize RGB values to match the input tensor's expected range.
- **Run Inference**: Invoke the interpreter and process the output.

Make sure that your model (`model.h`) is correctly compiled from your TensorFlow Lite model and included in the project. Adjust any paths or constants as necessary based on your specific setup.

