  // Initialize Serial communication
  Serial.begin(9600);

  // Initialize the APDS-9960 sensor
  if (!apds.init()) {
    Serial.println("Failed to initialize APDS-9960! Exiting...");
    while (1);
  }
  apds.enableColor(true);

  // Load the model and allocate memory for tensors
  interpreter.AllocateTensors();

  // Retrieve input tensor details
  TfLiteTensor* input = interpreter.input(0);

  // Ensure compatibility with the application's input data
  if ((input->dims->size != 1) || (input->dims->data[0] != 3)) {
    TF_LITE_REPORT_ERROR(error_reporter, "Bad input tensor parameters in model");
    return;
  }

  // Additional setup for other non-ML components can be done here
}

void loop() {
  if (!apds.colorDataReady()) {
    delay(50);
    return;
  }

  // Read the color data from the APDS-9960 sensor
  uint16_t red, green, blue;
  apds.getColorData(&red, &green, &blue);

  // Normalize the RGB values to a range of 0.0 to 1.0
  float r = static_cast<float>(red) / 65535.0f;
  float g = static_cast<float>(green) / 65535.0f;
  float b = static_cast<float>(blue) / 65535.0f;

  // Copy the processed data into the model's input tensor buffer
  TfLiteTensor* input = interpreter.input(0);
  input->data.f[0] = r;
  input->data.f[1] = g;
  input->data.f[2] = b;

  // Run the inference using the TensorFlow Lite Micro interpreter
  if (interpreter.Invoke() != kTfLiteOk) {
    TF_LITE_REPORT_ERROR(error_reporter, "Invoke failed on given input data");
    return;
  }

  // Process the output tensor(s)
  TfLiteTensor* output = interpreter.output(0);
  uint8_t predicted_class = output->data.uint8[0];

  // Execute application-specific actions based on the inference result
  switch (predicted_class) {
    case 0:
      Serial.println("Apple \uF8FF"); // Unicode emoji for Apple
      break;
    case 1:
      Serial.println("Banana \uD83C\uDF4C"); // Unicode emoji for Banana
      break;
    case 2:
      Serial.println("Orange \uD83C\uDF4A"); // Unicode emoji for Orange
      break;
    default:
      Serial.println("Unknown object");
      break;
  }
}
