// Create an error reporter instance
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Define the model and interpreter
const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  error_reporter->Report("Model schema version (%d) not supported by this version of TensorFlow Lite.\n",
                         model->version());
  return;
}

// Define the tensor arena
#define TENSOR_ARENA_SIZE (2048)
uint8_t tensor_arena[TENSOR_ARENA_SIZE];

// Define an operator resolver and interpreter
tflite::ops::micro::AllOpsResolver resolver;

tflite::MicroInterpreter interpreter(model, resolver, tensor_arena,
                                     TENSOR_ARENA_SIZE, error_reporter);

// Allocate memory for tensors
TfLiteStatus allocate_status = interpreter.AllocateTensors();
if (allocate_status != kTfLiteOk) {
  error_reporter->Report("AllocateTensors() failed\n");
  return;
}

// Define input and output tensor pointers
float* input = interpreter.input(0)->data.f;
uint8_t* output = interpreter.output(0)->data.uint8;

