  // Start serial communication for debugging/output
  Serial.begin(9600);

  // Initialize the LSM9DS1 sensor (assuming it's used for RGB color sensing)
  if (!IMU.begin()) {
    error_reporter->Report("Failed to initialize IMU!\n");
    while (true);
  }
}

void loop() {
  // Simulate reading from an RGB sensor
  // Replace with actual sensor readings in production
  input[0] = 0.562; // Red
  input[1] = 0.237; // Green
  input[2] = 0.200; // Blue

