    while (1);
  }
  Serial.println("Loaded model successfully");

  // Create an operator resolver with all available operators
  tflite::AllOpsResolver resolver;

  // Build the interpreter
  interpreter = new tflite::MicroInterpreter(model, resolver, tensor_arena, tensor_arena_size, error_reporter);

  // Allocate tensors
  if (interpreter->AllocateTensors() != kTfLiteOk) {
    error_reporter->Report("Failed to allocate tensors!");
    while (1);
  }
