```cpp
#include <TensorFlowLite.h>
#include <Wire.h>
#include <Adafruit_APDS9960.h>
#include "model.h"

// Initialize the APDS-9960 color sensor
Adafruit_APDS9960 apds;

// TensorFlow Lite globals
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;
const tflite::Model* model = tflite::GetModel(g_model);
tflite::ops::micro::AllOpsResolver resolver;
uint8_t tensor_arena[2048];
tflite::MicroInterpreter interpreter(model, resolver, tensor_arena, sizeof(tensor_arena), error_reporter);

// Input and output tensors
TfLiteTensor* input_tensor = nullptr;
TfLiteTensor* output_tensor = nullptr;

const char* class_names[] = {"Apple", "Banana", "Orange"};

void setup() {
  Serial.begin(9600);

  // Initialize the APDS-9960 color sensor
  if (!apds.begin()) {
    Serial.println("Failed to initialize APDS-9960");
    while (1) delay(10);
  }
  apds.enableColor(true);

  // Load and allocate tensors
  if (interpreter.AllocateTensors() != kTfLiteOk) {
    error_reporter->Report("AllocateTensors() failed");
    return;
  }

  // Obtain pointers to input and output tensors
  input_tensor = interpreter.input(0);
  output_tensor = interpreter.output(0);

  Serial.println("Setup complete!");
}

void loop() {
  uint16_t r, g, b, c;

  // Read color data from the sensor
  if (apds.colorAvailable()) {
    apds.getColorData(&r, &g, &b, &c);

    // Normalize RGB values to [0, 1]
    float red = static_cast<float>(r) / c;
    float green = static_cast<float>(g) / c;
    float blue = static_cast<float>(b) / c;

    // Copy normalized RGB values into the input tensor
    input_tensor->data.f[0] = red;
    input_tensor->data.f[1] = green;
    input_tensor->data.f[2] = blue;

    // Run inference
    if (interpreter.Invoke() != kTfLiteOk) {
      error_reporter->Report("Invoke failed");
      return;
    }

    // Process output
    uint8_t predicted_class = output_tensor->data.uint8[0];
    Serial.print("Predicted Class: ");
    Serial.println(class_names[predicted_class]);

    // Optionally add emojis based on the class
    switch (predicted_class) {
      case 0:
        Serial.println("\U0001F34E"); // Apple emoji
        break;
      case 1:
        Serial.println("\U0001F34C"); // Banana emoji
        break;
      case 2:
        Serial.println("\U0001F34A"); // Orange emoji
        break;
      default:
        Serial.println("Unknown class");
    }
  }

  delay(500); // Delay for readability and sensor stability
}
```

