#include "model.h"

// Define the tensor arena size
constexpr int kTensorArenaSize = 2048;
uint8_t tensor_arena[kTensorArenaSize];

// Create an error reporter instance
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Create the model interpreter and associated objects
const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  error_reporter->Report("Model schema version %d not supported\n", model->version());
  return;
}

tflite::ops::micro::AllOpsResolver resolver;

// Create the interpreter
tflite::MicroInterpreter interpreter(model, resolver, tensor_arena, kTensorArenaSize, error_reporter);

// Allocate memory for tensors
interpreter.AllocateTensors();

// Get pointers to the model's input and output tensors
tfLiteTensor* input = interpreter.input(0);
if ((input->dims->size != 2) || (input->dims->data[1] != 3)) {
  error_reporter->Report("Bad input tensor parameters in model");
  return;
}

// Create an instance of the APDS9960 sensor
Adafruit_APDS9960 apds;

void setup() {
  // Start the serial communication
  Serial.begin(9600);

  // Initialize the APDS-9960 (configure I2C and initial values)
  if (!apds.begin()) {
    error_reporter->Report("Failed to initialize APDS-9960!");
    return;
  }
  apds.enableColor(true);

  // Allocate memory for tensors
  TfLiteStatus allocate_status = interpreter.AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    error_reporter->Report("AllocateTensors() failed");
    return;
  }

  // Ensure the model's input tensor is float32
  TF_LITE_ASSERT_EQUAL(input->type, kTfLiteFloat32);
}

void loop() {
  uint16_t red, green, blue;

  if (apds.colorGetRed(&red) && apds.colorGetGreen(&green) && apds.colorGetBlue(&blue)) {
    float r = static_cast<float>(red) / 65535.0f;
    float g = static_cast<float>(green) / 65535.0f;
    float b = static_cast<float>(blue) / 65535.0f;

    // Copy RGB values to the input tensor
    input->data.f[0] = r;
    input->data.f[1] = g;
    input->data.f[2] = b;

    // Run the inference
    TfLiteStatus invoke_status = interpreter.Invoke();
    if (invoke_status != kTfLiteOk) {
      error_reporter->Report("Invoke failed");
      return;
    }

    // Read the output tensor
    tfLiteTensor* output = interpreter.output(0);
    uint8_t predicted_class = output->data.uint8[0];

    // Map the class index to an emoji or label
    const char* class_labels[] = {"🍎", "🍌", "🍊"};
