tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Define the model and interpreter variables
const tflite::Model* model = nullptr;
tflite::AllOpsResolver resolver;
tflite::MicroInterpreter* interpreter = nullptr;

// Create an instance of the APDS9960 color sensor
Adafruit_APDS9960 apds;

void setup() {
  // Initialize serial communication
  Serial.begin(9600);

  // Initialize the APDS9960 color sensor
  if (!apds.begin()) {
    Serial.println("Error initializing APDS-9960");
    while (1);
  }

  // Enable color sensing
  apds.enableColor(true);
  delay(2);  // Small delay to let the sensor initialize

  // Load and validate the model
  model = tflite::GetModel(g_model);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    error_reporter->Report("Error: Model schema version does not match\nExpected %d found %d\n", TFLITE_SCHEMA_VERSION, model->version());
    while (1);
  }

  // Build the interpreter
  static tflite::MicroInterpreter static_interpreter(model, resolver, tensor_arena, kTensorArenaSize, error_reporter);
  interpreter = &static_interpreter;

  // Allocate tensors
  if (interpreter->AllocateTensors() != kTfLiteOk) {
    error_reporter->Report("Error: AllocateTensors failed\n");
    while (1);
  }

  // Define model input tensor details
  TfLiteTensor* input = interpreter->input(0);
}

void loop() {
  uint16_t r, g, b, c;

  if (!apds.colorDataReady()) return;  // Wait for color data to be ready

  // Read the color values
  apds.getColorData(&r, &g, &b, &c);

  // Normalize the colors (assuming maximum value of 65535)
  float red = static_cast<float>(r) / 65535.0f;
  float green = static_cast<float>(g) / 65535.0f;
  float blue = static_cast<float>(b) / 65535.0f;

  // Copy normalized color data to the model input tensor
  TfLiteTensor* input = interpreter->input(0);
  input->data.f[0] = red;
  input->data.f[1] = green;
  input->data.f[2] = blue;

  // Run inference
  if (interpreter->Invoke() != kTfLiteOk) {
    error_reporter->Report("Error: Invoke failed\n");
    while (1);
  }

  // Process the output tensor
