```cpp
#include <TensorFlowLite.h>
#include <Wire.h>
#include <SparkFun_APDS9960.h>
#include "model.h"

// Declare TensorFlow Lite Micro variables
tflite::ErrorReporter error_reporter;
const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  error_reporter.Report("Model schema version (%d) not supported", model->version());
  return;
}

tflite::ops::micro::AllOpsResolver resolver;

// Define tensor arena
uint8_t tensor_arena[5000];

// Create the interpreter
tflite::MicroInterpreter interpreter(model, resolver, tensor_arena, sizeof(tensor_arena), &error_reporter);

// Allocate memory for tensors
TfLiteStatus allocate_status = interpreter.AllocateTensors();
if (allocate_status != kTfLiteOk) {
  error_reporter.Report("AllocateTensors() failed");
  return;
}

// Get input tensor pointer and size
TfLiteTensor* input_tensor = interpreter.input(0);
if ((input_tensor == nullptr) || (input_tensor->dims->size != 1) ||
    (input_tensor->dims->data[0] != 3) || (input_tensor->type != kTfLiteFloat32)) {
  error_reporter.Report("Bad input tensor parameters in model");
  return;
}

// APDS9960 RGB Sensor
SparkFun_APDS9960 apds;

void setup() {
  Serial.begin(9600);

  // Initialize the sensor
  if (apds.init()) {
    Serial.println(F("APDS-9960 initialization complete"));
  } else {
    Serial.println(F("Something went wrong during APDS-9960 init!"));
  }

  // Start running the APDS-9960 RGB and ambient light sensor (no gesture sensing)
  if (apds.enableColorSensor(false)) {
    Serial.println(F("Color sensor is now running"));
  } else {
    Serial.println(F("Something went wrong during color config!"));
  }
}

void loop() {
  uint16_t red, green, blue;

  // Read the RGB values
  if (!apds.getColor(&red, &green, &blue)) {
    Serial.println(F("Error reading color values"));
  } else {
    // Normalize the RGB values to be between 0 and 1
    float total = red + green + blue;
    float normRed = static_cast<float>(red) / total;
    float normGreen = static_cast<float>(green) / total;
    float normBlue = static_cast<float>(blue) / total;

    // Copy normalized values to input tensor
    float* input = interpreter.input(0)->data.f;
    input[0] = normRed;
    input[1] = normGreen;
    input[2] = normBlue;

    // Run the inference
    TfLiteStatus invoke_status = interpreter.Invoke();
    if (invoke_status != kTfLiteOk) {
      error_reporter.Report("Invoke failed");
      return;
    }

    // Get output tensor pointer and size
    TfLiteTensor* output_tensor = interpreter.output(0);
    uint8_t class_index = *output_tensor->data.uint8;

    // Print the result with corresponding emoji
    switch (class_index) {
      case 0:
        Serial.println(F("\uF8FF Apple")); // 🏺 Apple Emoji
        break;
      case 1:
        Serial.println(F("\U0001F34C Banana")); // 🍌 Banana Emoji
        break;
      case 2:
        Serial.println(F("\U0001F34A Orange")); // 🍊 Orange Emoji
        break;
      default:
        Serial.println(F("Unknown class"));
    }
  }

  delay(1000); // Delay for a second before next reading
}
```

