if (model->version() != TFLITE_SCHEMA_VERSION) {
  error_reporter->Report("Model schema version does not match expected version.\n");
}

// Declare an operator resolver that will decide which TensorFlow Lite ops to support.
tflite::AllOpsResolver resolver;

