  }
}

void loop() {
  uint16_t red, green, blue;

  // Read the color values from the APDS-9960
  if (apds.getColor(&red, &green, &blue)) {
    float norm_red = static_cast<float>(red) / 1023.0;
    float norm_green = static_cast<float>(green) / 1023.0;
    float norm_blue = static_cast<float>(blue) / 1023.0;

    // Set the input tensor data
    float* input = interpreter.input(0)->data.f;
    input[0] = norm_red;
    input[1] = norm_green;
    input[2] = norm_blue;

    // Run the inference
    if (interpreter.Invoke() != kTfLiteOk) {
      error_reporter->Report("Invoke failed on TensorFlow Lite model");
      return;
    }

    // Process the output tensor data
    uint8_t* output = interpreter.output(0)->data.uint8;
    int class_index = static_cast<int>(*output);

    // Map the class index to a corresponding emoji and print it
    switch (class_index) {
