```cpp
#include <TensorFlowLite.h>
#include <Wire.h>
#include <Adafruit_APDS9960.h>
#include "model.h"

// Error reporter for debug logs
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Define the model and interpreter pointers
const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  error_reporter->Report("Model schema version not supported\n");
}

// Define a tensor arena for memory allocation
static constexpr int kTensorArenaSize = 10240;
uint8_t tensor_arena[kTensorArenaSize];

// Op resolver and interpreter
tflite::ops::micro::AllOpsResolver resolver;
tflite::MicroInterpreter* interpreter;

// Input and output tensors
 TfLiteTensor* input_tensor;
 TfLiteTensor* output_tensor;

// APDS9960 sensor object
Adafruit_APDS9960 apds;

void setup() {
  // Start serial communication for debugging
  Serial.begin(9600);

  // Initialize the color sensor
  if (!apds.begin()) {
    error_reporter->Report("Failed to initialize APDS9960\n");
    while (1);
  }
  apds.enableColor(true);

  // Load and allocate model
  interpreter = new tflite::MicroInterpreter(model, resolver, tensor_arena,
                                              kTensorArenaSize, error_reporter);
  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    error_reporter->Report("AllocateTensors() failed\n");
    while (1);
  }

  // Get input and output tensor pointers
  input_tensor = interpreter->input(0);
  output_tensor = interpreter->output(0);

  if ((input_tensor->dims->size != 1) || (input_tensor->dims->data[0] != 3)) {
    error_reporter->Report("Bad input tensor dims!\n");
    while (1);
  }

  if ((output_tensor->dims->size != 1) || (output_tensor->dims->data[0] != 1)) {
    error_reporter->Report("Bad output tensor dims!\n");
    while (1);
  }
}

void loop() {
  uint16_t red, green, blue;

  // Read the color sensor values
  if (!apds.colorGetRed(&red) || !apds.colorGetGreen(&green) || !apds.colorGetBlue(&blue)) {
    error_reporter->Report("Failed to read APDS9960\n");
    while (1);
  }

  // Normalize the color values to [0, 1]
  float r = red / 65535.0;
  float g = green / 65535.0;
  float b = blue / 65535.0;

  // Copy normalized RGB values to input tensor
  input_tensor->data.f[0] = r;
  input_tensor->data.f[1] = g;
  input_tensor->data.f[2] = b;

  // Run the inference
  TfLiteStatus invoke_status = interpreter->Invoke();
  if (invoke_status != kTfLiteOk) {
    error_reporter->Report("Invoke failed\n");
    while (1);
  }

  // Get and process the output tensor
  uint8_t predicted_class = output_tensor->data.uint8[0];
  const char* class_name;
  switch (predicted_class) {
    case 0:
      class_name = "Apple";  // Unicode emoji: \uF8FF or ASCII 'A'
      break;
    case 1:
      class_name = "Banana"; // Unicode emoji: \uF8FF or ASCII 'B'
      break;
    case 2:
      class_name = "Orange"; // Unicode emoji: \uF8FF or ASCII 'O'
      break;
    default:
      class_name = "Unknown";
      break;
  }

  // Print the predicted class to serial
  Serial.print("Predicted Class: ");
  Serial.println(class_name);

  delay(1000); // Delay for readability
}
