#include <Wire.h>
#include <Adafruit_APDS9960.h>
#include "TensorFlowLite.h"
#include "tensorflow/lite/micro/all_ops_resolver.h"
#include "tensorflow/lite/micro/micro_error_reporter.h"
#include "tensorflow/lite/micro/micro_interpreter.h"
#include "tensorflow/lite/schema/schema_generated.h"

// Include the model header file
#include "model.h"

// Define tensor arena size
const int TENSOR_ARENA_SIZE = 10240;
uint8_t tensor_arena[TENSOR_ARENA_SIZE];

// Create an error reporter object
tflite::MicroErrorReporter micro_error_reporter;

// Declare the model pointer, interpreter, and resolver objects
const tflite::Model* model = nullptr;
tflite::MicroInterpreter* interpreter = nullptr;
tflite::AllOpsResolver resolver;

// Define an input tensor pointer
float* input = nullptr;

// Initialize APDS9960 sensor
Adafruit_APDS9960 apds;

// Function to initialize the model and interpreter
void setup_model() {
  // Load the model from the header file
  model = tflite::GetModel(g_model);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    micro_error_reporter.Report("Model schema version does not match expected version\n");
    return;
  }

  // Create an interpreter to run the model
  static tflite::MicroInterpreter static_interpreter(model, resolver, tensor_arena, TENSOR_ARENA_SIZE, &micro_error_reporter);
  interpreter = &static_interpreter;

  // Allocate memory from the tensor arena for tensors
  TfLiteStatus allocate_status = interpreter->AllocateTensors();
  if (allocate_status != kTfLiteOk) {
    micro_error_reporter.Report("AllocateTensors() failed\n");
    return;
  }

  // Get a pointer to the model's input tensor
  input = interpreter->input(0)->data.f;
}

// Function to initialize the APDS9960 sensor
void setup_sensor() {
  if (!apds.begin()) {
    micro_error_reporter.Report("Failed to initialize APDS-9960 sensor\n");
    return;
  }

  // Enable color sensor
  apds.enableColor(true);

  // Set integration time and gain
  apds.setIntegrationTime(APDS9960_INTEGRATIONTIME_154MS);
  apds.setGain(APDS9960_GAIN_64X);
}

void setup() {
  Serial.begin(9600);

  // Initialize the model and interpreter
  setup_model();

  // Initialize the APDS-9960 sensor
  setup_sensor();
}

void loop() {
  uint16_t red, green, blue, clear;

  if (apds.getColor(&red, &green, &blue)) {
