#include <Wire.h>
#include <Adafruit_APDS9960.h>
#include "TensorFlowLite.h"
#include "tensorflow/lite/micro/all_ops_resolver.h"
#include "tensorflow/lite/micro/micro_error_reporter.h"
#include "tensorflow/lite/micro/micro_interpreter.h"

// Include the model header file
#include "model.h"

// Create an error reporter instance
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Define a buffer to hold the model data
const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  error_reporter->Report("Model schema version (%d) not supported\n", model->version());
}

// Create an interpreter to run the model
static tflite::AllOpsResolver resolver;

// Define a tensor arena for storing intermediate buffers
constexpr int kTensorArenaSize = 4096;
uint8_t tensor_arena[kTensorArenaSize];

tflite::MicroInterpreter interpreter(model, resolver, tensor_arena, kTensorArenaSize, error_reporter);

// Allocate memory from the tensor arena for tensors
TfLiteStatus allocate_status = interpreter.AllocateTensors();
if (allocate_status != kTfLiteOk) {
  error_reporter->Report("AllocateTensors() failed\n");
}

// Define input and output tensors
TfLiteTensor* input_tensor = interpreter.input(0);
TfLiteTensor* output_tensor = interpreter.output(0);

// Create an instance of the color sensor
Adafruit_APDS9960 apds;

void setup() {
  Serial.begin(9600);

  // Initialize the APDS-9960 (color sensor)
  if (!apds.begin()) {
    error_reporter->Report("Failed to initialize APDS-9960! Check your wiring.\n");
    while (1);
  }

  // Configure the color sensor
  apds.enableColor(true);

  // Allocate memory for tensors
  if (allocate_status != kTfLiteOk) {
    error_reporter->Report("AllocateTensors() failed\n");
    return;
  }
}

void loop() {
  // Read raw color values from the sensor
  uint16_t r, g, b, c;
  apds.getColorData(&r, &g, &b, &c);

  // Normalize the RGB values to the range [0.0, 1.0]
  float normalized_r = static_cast<float>(r) / 4095.0f;
  float normalized_g = static_cast<float>(g) / 4095.0f;
  float normalized_b = static_cast<float>(b) / 4095.0f;

  // Copy the processed data into the model's input tensor
  input_tensor->data.f[0] = normalized_r;
  input_tensor->data.f[1] = normalized_g;
  input_tensor->data.f[2] = normalized_b;

  // Run inference on the model
  TfLiteStatus invoke_status = interpreter.Invoke();
  if (invoke_status != kTfLiteOk) {
    error_reporter->Report("Invoke failed\n");
    return;
  }

  // Process the output tensor and print the result
  uint8_t predicted_class = output_tensor->data.uint8[0];
  switch (predicted_class) {
    case 0:
      Serial.println("🍎 Apple"); // Unicode for apple emoji
      break;
    case 1:
      Serial.println("🍌 Banana"); // Unicode for banana emoji
      break;
    case 2:
      Serial.println("🍊 Orange"); // Unicode for orange emoji
      break;
    default:
      Serial.println("Unknown class");
      break;
  }

  delay(500); // Wait before the next reading
}
