#include <Wire.h>
#include <Adafruit_APDS9960.h>
#include <TensorFlowLite.h>
#include "tensorflow/lite/micro/all_ops_resolver.h"
#include "tensorflow/lite/micro/micro_error_reporter.h"
#include "tensorflow/lite/micro/micro_interpreter.h"
#include "model.h"  // Ensure the model header is correctly included

// Create an instance of the error reporter
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Define the model input and output tensors
const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  error_reporter->Report("Model schema version %d not supported\n", model->version());
  return;
}

// Create an operator resolver that can find all the operations in the model
tflite::ops::micro::AllOpsResolver resolver;

// Define the tensor arena size and allocate memory for it
const int tensor_arena_size = 4096;
uint8_t tensor_arena[tensor_arena_size];

// Create an interpreter to run the model with the provided allocator, resolver, and error reporter
tflite::MicroInterpreter interpreter(model, resolver, tensor_arena, tensor_arena_size, error_reporter);

// Allocate memory from the tensor arena for the model's tensors
TfLiteStatus allocate_status = interpreter.AllocateTensors();
if (allocate_status != kTfLiteOk) {
  error_reporter->Report("AllocateTensors() failed\n");
  return;
}

// Get pointers to the model's input and output tensors
TfLiteTensor* input = interpreter.input(0);
TfLiteTensor* output = interpreter.output(0);

// Initialize the color sensor
Adafruit_APDS9960 apds;

void setup() {
  Serial.begin(9600);

  // Initialize APDS-9960 (configure I2C and interrupts)
  if (!apds.begin()) {
    Serial.println("Failed to initialize APDS-9960! Check your wiring.");
    while (1);
  }

  // Enable the color sensor
  apds.enableColor(true);

  // Delay for a bit to let the sensor settle
  delay(100);
}

void loop() {
  // Read the color data from the sensor
  uint16_t r = apds.readRed();
  uint16_t g = apds.readGreen();
  uint16_t b = apds.readBlue();

  // Normalize the RGB values to a range between 0 and 1
  float red = r / 255.0f;
  float green = g / 255.0f;
  float blue = b / 255.0f;

  // Copy the normalized RGB values into the input tensor
  input->data.f[0] = red;
  input->data.f[1] = green;
  input->data.f[2] = blue;

  // Run the inference
  TfLiteStatus invoke_status = interpreter.Invoke();
  if (invoke_status != kTfLiteOk) {
    error_reporter->Report("Invoke failed\n");
    return;
  }

  // Read the predicted class from the output tensor
  int predicted_class = output->data.uint8[0];

  // Print the predicted class with corresponding emoji to Serial Monitor
  switch (predicted_class) {
    case 0:
      Serial.println("Apple \uF8FF");
      break;
    case 1:
      Serial.println("Banana \u1F34C");
      break;
    case 2:
      Serial.println("Orange \u1F34A");
      break;
    default:
      Serial.println("Unknown class");
      break;
  }

  // Delay before the next sensor reading
  delay(1000);
}
