  Serial.begin(9600);

  // Initialize the color sensor
  if (!apds.begin()) {
    error_reporter->Report("Failed to initialize APDS9960");
    while (1);
  }

  // Enable color sensing and set integration time
  apds.enableColor(true);
  apds.setIntegrationTime(APDS9960_INTEGRATIONTIME_25MS);
}

void loop() {
  uint16_t r, g, b;

  // Read the color sensor values
  if (apds.colorAvailable()) {
    apds.getColorData(&r, &g, &b);

    // Normalize the RGB values to [0.0, 1.0]
    float red = static_cast<float>(r) / 65535.0f;
    float green = static_cast<float>(g) / 65535.0f;
    float blue = static_cast<float>(b) / 65535.0f;

    // Copy the normalized values into the model's input tensor
    float* input = interpreter.input(0)->data.f;
    input[0] = red;
    input[1] = green;
    input[2] = blue;

    // Run inference
    if (interpreter.Invoke() != kTfLiteOk) {
      error_reporter->Report("Invoke failed");
      return;
    }

    // Get the output of the model
    uint8_t* output = interpreter.output(0)->data.uint8;

    // Map the output to a class name and print it
    switch (output[0]) {
      case 0:
        Serial.println("Apple \uF8FF"); // Apple emoji: 🍏
        break;
      case 1:
        Serial.println("Banana \uD83C\uDF4C"); // Banana emoji: 🥋
