#include "TensorFlowLite.h"
#include "tensorflow/lite/micro/all_ops_resolver.h"
#include "tensorflow/lite/micro/micro_error_reporter.h"
#include "tensorflow/lite/micro/micro_interpreter.h"
#include "model.h"

// Define the tensor arena size
#define TENSOR_ARENA_SIZE (16384)

// Create an instance of the APDS9960 RGB sensor library
APDS9960 apds;

// Declare variables for TensorFlow Lite Micro
tflite::MicroErrorReporter error_reporter;
const tflite::Model* model = nullptr;
tflite::ops::micro::AllOpsResolver resolver;
uint8_t tensor_arena[TENSOR_ARENA_SIZE];
tflite::MicroInterpreter interpreter(model, resolver, tensor_arena, TENSOR_ARENA_SIZE, &error_reporter);

// Variables to store sensor data
uint16_t red = 0;
uint16_t green = 0;
uint16_t blue = 0;

void setup() {
  // Initialize serial communication for debugging and output
  Serial.begin(9600);

  // Initialize the APDS9960 RGB sensor
  if (!apds.init()) {
    Serial.println("APDS-9960 initialization failed!");
    while (1);
  }

  // Enable color sensor module
  apds.enableColorSensor(true);

  // Load the model from flash memory
  model = tflite::GetModel(g_model);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    Serial.println("Error: Model schema version does not match interpreter!");
    while (1);
  }

  // Instantiate and prepare the interpreter
  interpreter.AllocateTensors();

  // Check for allocation errors
  if (interpreter.allocation_failed()) {
    Serial.println("TensorFlow Lite Micro memory allocation failed!");
    while (1);
  }

  // Define input tensor
  TfLiteTensor* input = interpreter.input(0);

  // Ensure the input tensor has the correct shape and type
  if ((input->dims->size != 2) || (input->dims->data[0] != 1) || (input->dims->data[1] != 3)) {
    Serial.println("Input tensor dimensions do not match expected shape!");
    while (1);
  }

  // Ensure the input tensor data type is float
  if (input->type != kTfLiteFloat32) {
    Serial.println("Input tensor data type does not match expected type!");
    while (1);
  }
}

void loop() {
  // Read color data from APDS9960 sensor
  apds.getColorData(&red, &green, &blue);

  // Normalize the RGB values to [0.0, 1.0]
  float normalized_red = static_cast<float>(red) / 65535.0f;
  float normalized_green = static_cast<float>(green) / 65535.0f;
  float normalized_blue = static_cast<float>(blue) / 65535.0f;

  // Set the input tensor data
  TfLiteTensor* input = interpreter.input(0);
  input->data.f[0] = normalized_red;
  input->data.f[1] = normalized_green;
  input->data.f[2] = normalized_blue;

  // Run inference
  if (interpreter.Invoke() != kTfLiteOk) {
    Serial.println("Error during inference!");
    return;
  }

  // Get the output tensor data
  TfLiteTensor* output = interpreter.output(0);
  uint8_t predicted_class = output->data.uint8[0];

  // Map the predicted class to an emoji and print it
  switch (predicted_class) {
    case 0:
      Serial.println("Apple \uF8FF");  // Apple Emoji
      break;
    case 1:
      Serial.println("Banana \uD83C\uDF4C");  // Banana Emoji
      break;
    case 2:
      Serial.println("Orange \uD83C\uDF4A");  // Orange Emoji
      break;
    default:
      Serial.println("Unknown class");
      break;
  }

  // Delay between readings
  delay(1000);
}
