Based on the provided dataset information and application specifications, we will create a complete Arduino sketch that uses TensorFlow Lite Micro to classify objects based on RGB color sensor input from an APDS9960 sensor. The code will follow the phases outlined in your programming guidelines.

Here's the complete sketch:

```cpp
#include <TensorFlowLite.h>
#include <tensorflow/lite/micro/all_ops_resolver.h>
#include <tensorflow/lite/micro/micro_error_reporter.h>
#include <tensorflow/lite/micro/micro_interpreter.h>
#include <Arduino_APDS9960.h>
#include <Wire.h>

// Load the model from a header file
#define MODEL_TFLITE "model.tflite"
#include "./model.h"

namespace {
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

const tflite::Model* model = tflite::GetModel(g_model);
if (model->version() != TFLITE_SCHEMA_VERSION) {
  error_reporter->Report("Model schema version does not match expected version.\n");
  return;
}

tflite::ops::micro::AllOpsResolver resolver;

// Create an area of memory to use for input, output, and intermediate arrays.
constexpr int kTensorArenaSize = 2048;
uint8_t tensor_arena[kTensorArenaSize];

// Build an interpreter to run the model with
tflite::MicroInterpreter interpreter(model, resolver, tensor_arena, kTensorArenaSize, error_reporter);

TfLiteStatus allocate_status = interpreter.AllocateTensors();
if (allocate_status != kTfLiteOk) {
  error_reporter->Report("AllocateTensors() failed\n");
  return;
}

// Get pointers to the model's input and output tensors.
float* input = interpreter.input(0)->data.f;
uint8_t* output = interpreter.output(0)->data.uint8;

APDS9960 apds;

const char* class_names[] = {"Apple", "Banana", "Orange"};
}  // namespace

void setup() {
  Serial.begin(9600);

  if (!apds.init()) {
    error_reporter->Report("Failed to initialize APDS-9960 sensor!\n");
    while (1);
  }

  apds.enableColorSensor(true);
}

void loop() {
  uint16_t red, green, blue;

  if (apds.getColor(&red, &green, &blue)) {
    // Normalize RGB values to [0.0, 1.0] range
    float r = red / 255.0f;
    float g = green / 255.0f;
    float b = blue / 255.0f;

    // Copy normalized RGB values into the input tensor
    input[0] = r;
    input[1] = g;
    input[2] = b;

    // Run inference
    TfLiteStatus invoke_status = interpreter.Invoke();
    if (invoke_status != kTfLiteOk) {
      error_reporter->Report("Invoke failed!\n");
      return;
    }

    // Get predicted class
    uint8_t predicted_class = output[0];

    // Print the result to serial monitor
    Serial.print("Predicted class: ");
    Serial.println(class_names[predicted_class]);
  }
}
```

### Explanation:
1. **Libraries and Model**: Include necessary libraries and load the model from a header file.
2. **TensorFlow Lite Setup**:
   - Declare `ErrorReporter`, `ModelPointer`, `Interpreter`, and `InputPointer`.
   - Define and allocate a tensor arena buffer.
   - Load the model, register operators, instantiate the interpreter, and allocate memory for tensors.
3. **Sensor Initialization**: Initialize the APDS9960 sensor in the `setup()` function.
4. **Data Collection and Inference**:
   - Continuously read RGB values from the sensor in the `loop()` function.
   - Normalize RGB values to a range of [0.0, 1.0].
   - Copy normalized values into the model's input tensor.
   - Run inference using `interpreter.Invoke()`.
5. **Output**: Print the predicted class name to the serial monitor.

Make sure you have the `model.h` file generated from your TensorFlow Lite model and that it matches the specified path in the code.

