```cpp
#include <TensorFlowLite.h>
#include <tensorflow/lite/micro/all_ops_resolver.h>
#include <tensorflow/lite/micro/micro_error_reporter.h>
#include <tensorflow/lite/micro/micro_interpreter.h>
#include <Wire.h>
#include <Adafruit_APDS9960.h>

#include "model.h"

// Define the tensor arena size
constexpr int kTensorArenaSize = 4096;
uint8_t tensor_arena[kTensorArenaSize];

// Create an error reporter instance
tflite::MicroErrorReporter micro_error_reporter;
tflite::ErrorReporter* error_reporter = &micro_error_reporter;

// Declare the model pointer, interpreter and input/output tensors
const tflite::Model* model = nullptr;
tflite::AllOpsResolver resolver;
tflite::MicroInterpreter* interpreter = nullptr;
TfLiteTensor* input_tensor = nullptr;
TfLiteTensor* output_tensor = nullptr;

// Create an instance of the color sensor
Adafruit_APDS9960 apds;

const char* object_classes[] = {"Apple", "Banana", "Orange"};

void setup() {
  // Initialize Serial communication
  Serial.begin(9600);

  // Initialize the color sensor
  if (!apds.init()) {
    Serial.println("APDS-9960 initialization failed");
    while (1);
  }

  // Enable color sensing
  apds.enableColor(true);
  delay(2);

  // Load and initialize the model
  model = tflite::GetModel(g_model);
  if (model->version() != TFLITE_SCHEMA_VERSION) {
    error_reporter->Report("Model schema version %d not supported\n", model->version());
    while (1);
  }

  interpreter = new tflite::MicroInterpreter(model, resolver, tensor_arena, kTensorArenaSize, error_reporter);

  // Allocate memory for the model
  if (interpreter->AllocateTensors() != kTfLiteOk) {
    error_reporter->Report("AllocateTensors() failed\n");
    while (1);
  }

  // Get pointers to input and output tensors
  input_tensor = interpreter->input(0);
  output_tensor = interpreter->output(0);

  Serial.println("Setup complete, ready for inference.");
}

void loop() {
  // Read the color data from the sensor
  uint16_t r, g, b, c;
  apds.getColorData(&r, &g, &b, &c);

  // Normalize RGB values to the range [0, 1]
  float red = static_cast<float>(r) / 1023.0f;
  float green = static_cast<float>(g) / 1023.0f;
  float blue = static_cast<float>(b) / 1023.0f;

  // Copy normalized RGB values into the model's input tensor
  input_tensor->data.f[0] = red;
  input_tensor->data.f[1] = green;
  input_tensor->data.f[2] = blue;

  // Run inference on the input data
  if (interpreter->Invoke() != kTfLiteOk) {
    error_reporter->Report("Invoke failed\n");
    return;
  }

  // Process the output tensor to get the classification result
  int predicted_class = static_cast<int>(output_tensor->data.uint8[0]);

  // Output the object class to serial using Unicode emojis
  if (predicted_class >= 0 && predicted_class < sizeof(object_classes) / sizeof(object_classes[0])) {
    Serial.print("Detected: ");
    Serial.println(object_classes[predicted_class]);
  } else {
    Serial.println("Unknown class");
  }

  // Delay before the next inference cycle
  delay(1000);
}
